/*
 * extraGlossary — a curated supplement of modern generative-AI / LLM terms that
 * fill gaps in the auto-generated GLOSSARY_TERMS set. Merged in GlossaryPage.jsx
 * and de-duplicated by (lowercased) term name, so anything already present in
 * the base list is ignored — no duplicates are ever shown.
 */
export const EXTRA_GLOSSARY_TERMS = [
  { term: 'Retrieval-Augmented Generation', abbr: 'RAG', category: 'AI/ML', definition: 'A technique that grounds a language model in external knowledge by retrieving relevant documents at query time and feeding them into the prompt as context, reducing hallucination and letting the model cite up-to-date or private data without retraining.', related: ['Vector Database', 'Embedding', 'Context Window', 'Hallucination'] },
  { term: 'Reinforcement Learning from Human Feedback', abbr: 'RLHF', category: 'AI/ML', definition: 'A training method that aligns a model with human preferences by collecting human rankings of model outputs, training a reward model on them, and fine-tuning the base model with reinforcement learning to maximize that reward.', related: ['Fine-Tuning', 'Reward Model', 'Alignment', 'Large Language Model'] },
  { term: 'Chain-of-Thought', abbr: 'CoT', category: 'AI/ML', definition: 'A prompting technique that asks a model to reason step by step before giving a final answer, improving performance on math, logic and multi-step tasks by making intermediate reasoning explicit.', related: ['Prompt Engineering', 'Reasoning', 'Few-Shot Learning'] },
  { term: 'Model Context Protocol', abbr: 'MCP', category: 'AI/ML', definition: 'An open standard that lets AI applications connect to external tools, data sources and services through a uniform interface, so models can read files, query databases and call APIs without bespoke integrations.', related: ['AI Agent', 'Tool Use', 'Function Calling'] },
  { term: 'AI Agent', abbr: null, category: 'AI/ML', definition: 'An autonomous system that uses a language model as a controller to plan, call tools, observe results and iterate toward a goal with minimal human intervention — going beyond single-shot text generation to take actions.', related: ['Agentic AI', 'Tool Use', 'Function Calling', 'Model Context Protocol'] },
  { term: 'Agentic AI', abbr: null, category: 'AI/ML', definition: 'A class of AI systems designed to act with autonomy — decomposing tasks, making decisions, using tools and adapting over multiple steps — rather than producing a single response to a single prompt.', related: ['AI Agent', 'Tool Use', 'Reasoning'] },
  { term: 'Tool Use', abbr: null, category: 'AI/ML', definition: "A model capability where the LLM decides to invoke external functions or APIs (search, code execution, database queries) and incorporates the results into its response, extending it beyond its training data.", related: ['Function Calling', 'AI Agent', 'Model Context Protocol'] },
  { term: 'Function Calling', abbr: null, category: 'AI/ML', definition: 'A feature that lets a language model output a structured request to call a developer-defined function with typed arguments, enabling reliable integration between natural-language prompts and real software actions.', related: ['Tool Use', 'AI Agent', 'Structured Output'] },
  { term: 'Temperature', abbr: null, category: 'AI/ML', definition: 'A sampling parameter that controls randomness in a language model’s output: low values make responses focused and deterministic, high values make them more diverse and creative.', related: ['Top-p Sampling', 'Inference', 'Large Language Model'] },
  { term: 'Top-p Sampling', abbr: 'Nucleus Sampling', category: 'AI/ML', definition: 'A decoding strategy that samples the next token from the smallest set of candidates whose cumulative probability exceeds a threshold p, balancing coherence and diversity better than fixed top-k sampling.', related: ['Temperature', 'Inference', 'Tokenization'] },
  { term: 'Knowledge Distillation', abbr: 'Distillation', category: 'AI/ML', definition: 'A compression technique where a smaller "student" model is trained to reproduce the outputs of a larger "teacher" model, retaining much of its quality at a fraction of the size and inference cost.', related: ['Quantization', 'Model Compression', 'Inference'] },
  { term: 'Mixture of Experts', abbr: 'MoE', category: 'AI/ML', definition: 'A model architecture that routes each input through only a few of many specialized sub-networks ("experts"), giving very large parameter counts while keeping the compute per token low.', related: ['Transformer', 'Parameter', 'Inference'] },
  { term: 'Low-Rank Adaptation', abbr: 'LoRA', category: 'AI/ML', definition: 'A parameter-efficient fine-tuning method that freezes the base model and trains small low-rank matrices injected into its layers, dramatically cutting the memory and storage cost of customizing large models.', related: ['Fine-Tuning', 'PEFT', 'Large Language Model'] },
  { term: 'Parameter-Efficient Fine-Tuning', abbr: 'PEFT', category: 'AI/ML', definition: 'A family of techniques (LoRA, adapters, prefix tuning) that adapt a large pretrained model to a new task by training only a small fraction of its parameters, instead of the whole network.', related: ['Low-Rank Adaptation', 'Fine-Tuning'] },
  { term: 'Prompt Injection', abbr: null, category: 'Security & SIEM', definition: 'An attack where malicious instructions hidden in user input or retrieved content trick a language model into ignoring its original instructions, leaking data or taking unintended actions.', related: ['Jailbreak', 'Guardrails', 'Retrieval-Augmented Generation'] },
  { term: 'Jailbreak', abbr: null, category: 'Security & SIEM', definition: 'A crafted prompt designed to bypass a model’s safety guardrails and elicit content or behavior the model was trained to refuse.', related: ['Prompt Injection', 'Guardrails', 'Alignment'] },
  { term: 'Guardrails', abbr: null, category: 'AI/ML', definition: 'Programmatic safety layers around an LLM that filter, validate or constrain its inputs and outputs — blocking unsafe content, enforcing formats and keeping the model on-task.', related: ['Alignment', 'Prompt Injection', 'Hallucination'] },
  { term: 'Alignment', abbr: null, category: 'AI/ML', definition: 'The research area and practice of making AI systems pursue intended human goals and values, behaving helpfully and harmlessly even as their capabilities grow.', related: ['RLHF', 'Guardrails', 'AI Safety'] },
  { term: 'AI Safety', abbr: null, category: 'AI/ML', definition: 'The field concerned with preventing harm from AI systems — covering robustness, alignment, interpretability and the avoidance of unintended or dangerous behavior.', related: ['Alignment', 'Guardrails', 'Red Teaming'] },
  { term: 'Red Teaming', abbr: null, category: 'Security & SIEM', definition: 'Adversarial testing in which experts deliberately probe an AI system for failures, unsafe outputs and exploitable weaknesses before deployment.', related: ['AI Safety', 'Jailbreak', 'Guardrails'] },
  { term: 'Reward Model', abbr: null, category: 'AI/ML', definition: 'A model trained on human preference data to score how good a candidate output is; used as the optimization signal in RLHF to fine-tune a base model toward preferred behavior.', related: ['RLHF', 'Fine-Tuning', 'Alignment'] },
  { term: 'Reasoning Model', abbr: null, category: 'AI/ML', definition: 'A language model trained or prompted to spend extra inference-time compute working through a problem step by step before answering, trading latency for accuracy on hard tasks.', related: ['Chain-of-Thought', 'Inference', 'Test-Time Compute'] },
  { term: 'Test-Time Compute', abbr: null, category: 'AI/ML', definition: 'The strategy of improving model answers by allocating more computation at inference (longer reasoning chains, sampling and selection) rather than by making the model larger.', related: ['Reasoning Model', 'Chain-of-Thought', 'Inference'] },
  { term: 'Context Window', abbr: null, category: 'AI/ML', definition: 'The maximum number of tokens a language model can attend to at once — its working memory for a request, spanning the prompt plus the generated response.', related: ['Tokenization', 'Large Language Model', 'Retrieval-Augmented Generation'] },
  { term: 'Token', abbr: null, category: 'AI/ML', definition: 'The atomic unit a language model reads and generates — typically a word piece or sub-word — produced by a tokenizer. Model cost and context limits are measured in tokens.', related: ['Tokenization', 'Context Window', 'Embedding'] },
  { term: 'Embedding', abbr: null, category: 'AI/ML', definition: 'A dense numerical vector that represents the meaning of text, images or other data so that semantically similar items sit close together in vector space — the backbone of search and RAG.', related: ['Vector Database', 'Semantic Search', 'Retrieval-Augmented Generation'] },
  { term: 'Semantic Search', abbr: null, category: 'AI/ML', definition: 'Search that matches by meaning rather than keywords, by comparing the embedding of a query against the embeddings of indexed content and ranking by vector similarity.', related: ['Embedding', 'Vector Database', 'Retrieval-Augmented Generation'] },
  { term: 'Hallucination', abbr: null, category: 'AI/ML', definition: 'When a generative model produces confident but false or fabricated information that is not grounded in its inputs or training data.', related: ['Retrieval-Augmented Generation', 'Guardrails', 'Grounding'] },
  { term: 'Grounding', abbr: null, category: 'AI/ML', definition: 'Connecting a model’s responses to verifiable external sources or real data so its claims can be traced and trusted, rather than invented.', related: ['Retrieval-Augmented Generation', 'Hallucination', 'Citation'] },
  { term: 'Foundation Model', abbr: null, category: 'AI/ML', definition: 'A large model pretrained on broad data at scale that can be adapted (via prompting or fine-tuning) to many downstream tasks — e.g. GPT, Gemini, Claude, Llama.', related: ['Large Language Model', 'Fine-Tuning', 'Pretraining'] },
  { term: 'Large Language Model', abbr: 'LLM', category: 'AI/ML', definition: 'A foundation model with billions of parameters trained on vast text corpora to predict the next token, capable of generating and understanding human language across tasks.', related: ['Foundation Model', 'Transformer', 'Token'] },
  { term: 'Small Language Model', abbr: 'SLM', category: 'AI/ML', definition: 'A compact language model (often a few billion parameters or fewer) designed to run efficiently on edge devices or at low cost, trading some capability for speed and privacy.', related: ['Large Language Model', 'Knowledge Distillation', 'Quantization'] },
  { term: 'Multimodal Model', abbr: null, category: 'AI/ML', definition: 'A model that processes and relates more than one type of data — such as text, images, audio and video — within a single system.', related: ['Foundation Model', 'Vision-Language Model', 'Embedding'] },
  { term: 'Vision-Language Model', abbr: 'VLM', category: 'AI/ML', definition: 'A multimodal model that jointly understands images and text, enabling captioning, visual question answering and image-grounded reasoning.', related: ['Multimodal Model', 'Foundation Model'] },
  { term: 'Diffusion Model', abbr: null, category: 'AI/ML', definition: 'A generative model that creates images, audio or video by learning to reverse a gradual noising process, denoising random input into coherent output — the basis of modern image generators.', related: ['Generative AI', 'Latent Space'] },
  { term: 'Generative AI', abbr: 'GenAI', category: 'AI/ML', definition: 'AI systems that produce new content — text, images, code, audio or video — rather than only classifying or predicting from existing data.', related: ['Foundation Model', 'Diffusion Model', 'Large Language Model'] },
  { term: 'Pretraining', abbr: null, category: 'AI/ML', definition: 'The initial, compute-intensive phase where a model learns general patterns from massive unlabeled data, before any task-specific fine-tuning.', related: ['Fine-Tuning', 'Foundation Model', 'Self-Supervised Learning'] },
  { term: 'Inference', abbr: null, category: 'AI/ML', definition: 'Running a trained model to produce outputs on new inputs. Inference cost, latency and throughput dominate the economics of deployed AI.', related: ['Quantization', 'Latency', 'Throughput'] },
  { term: 'Quantization', abbr: null, category: 'AI/ML', definition: 'Reducing the numerical precision of a model’s weights (e.g. from 16-bit to 4-bit) to shrink memory use and speed up inference, with minimal accuracy loss.', related: ['Knowledge Distillation', 'Inference', 'Small Language Model'] },
  { term: 'Prompt Engineering', abbr: null, category: 'AI/ML', definition: 'The practice of crafting and structuring inputs to a model to reliably get the desired output — including instructions, examples, formatting and reasoning cues.', related: ['Chain-of-Thought', 'Few-Shot Learning', 'System Prompt'] },
  { term: 'System Prompt', abbr: null, category: 'AI/ML', definition: 'A hidden, high-priority instruction that sets a model’s role, behavior and constraints for an entire conversation, distinct from per-message user prompts.', related: ['Prompt Engineering', 'Guardrails'] },
  { term: 'Few-Shot Learning', abbr: null, category: 'AI/ML', definition: 'Guiding a model to a task by including a handful of worked examples in the prompt, without any weight updates.', related: ['Zero-Shot Learning', 'Prompt Engineering', 'In-Context Learning'] },
  { term: 'Zero-Shot Learning', abbr: null, category: 'AI/ML', definition: 'Asking a model to perform a task it was never explicitly trained or shown examples for, relying solely on its pretrained general knowledge.', related: ['Few-Shot Learning', 'Prompt Engineering'] },
  { term: 'In-Context Learning', abbr: 'ICL', category: 'AI/ML', definition: 'A model’s ability to learn a task on the fly from examples and instructions placed in its prompt, without changing its weights.', related: ['Few-Shot Learning', 'Context Window', 'Prompt Engineering'] },
  { term: 'Vector Database', abbr: null, category: 'Databases', definition: 'A database optimized for storing and querying high-dimensional embedding vectors by similarity, powering semantic search and retrieval-augmented generation at scale.', related: ['Embedding', 'Semantic Search', 'Retrieval-Augmented Generation'] },
  { term: 'LLMOps', abbr: null, category: 'AIOps', definition: 'The practices and tooling for deploying, monitoring, evaluating and governing large language model applications in production — covering prompts, costs, latency, quality and safety.', related: ['MLOps', 'Observability', 'Evaluation'] },
  { term: 'AI Evaluation', abbr: 'Evals', category: 'AI/ML', definition: 'Systematic measurement of model quality against benchmarks, test sets or human/LLM judges, used to compare models and catch regressions before shipping.', related: ['LLMOps', 'Benchmark', 'LLM-as-a-Judge'] },
  { term: 'LLM-as-a-Judge', abbr: null, category: 'AI/ML', definition: 'Using a capable language model to score or compare other models’ outputs against criteria, a scalable (if imperfect) alternative to human evaluation.', related: ['AI Evaluation', 'Reward Model'] },
  { term: 'Structured Output', abbr: null, category: 'AI/ML', definition: 'Constraining a model to emit machine-readable formats such as JSON conforming to a schema, so its responses can be parsed and acted on reliably by software.', related: ['Function Calling', 'Tool Use'] },
  { term: 'Latent Space', abbr: null, category: 'AI/ML', definition: 'The compressed, abstract representation space a model learns, where each point encodes meaningful features and nearby points correspond to similar inputs.', related: ['Embedding', 'Diffusion Model'] },

  // ── Fundamentals ──────────────────────────────────────────────────────────
  { term: 'Observability', abbr: null, category: 'Fundamentals', definition: 'The ability to understand the internal state of a system from its external outputs — metrics, logs and traces — by asking arbitrary questions about behavior without deploying new code.', related: ['Monitoring', 'Telemetry', 'Three Pillars of Observability'] },
  { term: 'Monitoring', abbr: null, category: 'Fundamentals', definition: 'The practice of collecting predefined signals and alerting when known failure modes occur. Monitoring tells you when something is wrong; observability helps you understand why.', related: ['Observability', 'Alerting Rule', 'Health Check'] },
  { term: 'Telemetry', abbr: null, category: 'Fundamentals', definition: 'Automated collection and transmission of measurements and events from running systems — the raw data that powers metrics, logs and traces.', related: ['Instrumentation', 'Observability', 'OpenTelemetry'] },
  { term: 'Instrumentation', abbr: null, category: 'Fundamentals', definition: 'Code or configuration added to an application or infrastructure component to emit telemetry — counters, histograms, log lines and trace spans — about its behavior.', related: ['Telemetry', 'Bytecode Instrumentation', 'OpenTelemetry'] },
  { term: 'Three Pillars of Observability', abbr: null, category: 'Fundamentals', definition: 'The foundational telemetry types — metrics (aggregated numbers over time), logs (discrete event records) and traces (request paths across services) — that together provide a complete picture of system behavior.', related: ['Observability', 'Metrics', 'Logging', 'Tracing'] },
  { term: 'Service Level Objective', abbr: 'SLO', category: 'Fundamentals', definition: 'A target level of reliability for a service, expressed as a measurable threshold over a time window — e.g. 99.9% of requests complete in under 200 ms. SLOs drive engineering priorities and error budgets.', related: ['Service Level Indicator', 'Error Budget', 'Service Level Agreement'] },
  { term: 'Service Level Indicator', abbr: 'SLI', category: 'Fundamentals', definition: 'A quantitative measure of some aspect of service behavior — latency, availability, throughput or error rate — used as the basis for defining and evaluating SLOs.', related: ['Service Level Objective', 'Error Rate', 'Latency Budget'] },
  { term: 'Service Level Agreement', abbr: 'SLA', category: 'Fundamentals', definition: 'A contractual commitment between a provider and customer defining expected service performance, often with financial penalties for breaches. SLAs are typically stricter than internal SLOs.', related: ['Service Level Objective', 'Uptime', 'Downtime'] },
  { term: 'Error Budget', abbr: null, category: 'Fundamentals', definition: 'The allowable amount of unreliability before an SLO is breached — the gap between 100% and the SLO target. Teams can spend the error budget on risky changes; exhausting it triggers a reliability freeze.', related: ['Service Level Objective', 'Error Budget Policy', 'Burn Rate'] },
  { term: 'Mean Time to Recovery', abbr: 'MTTR', category: 'Fundamentals', definition: 'The average time to restore a service to normal operation after an incident is detected. A key reliability metric that reflects detection, diagnosis and remediation speed.', related: ['Mean Time to Detect', 'Incident Management', 'Downtime'] },
  { term: 'Mean Time to Detect', abbr: 'MTTD', category: 'Fundamentals', definition: 'The average elapsed time between when an incident begins and when it is first detected by monitoring or users. Lower MTTD reduces customer impact and recovery cost.', related: ['Mean Time to Recovery', 'Alerting Rule', 'Observability'] },
  { term: 'Mean Time to Acknowledge', abbr: 'MTTA', category: 'Fundamentals', definition: 'The average time between an alert firing and an on-call engineer acknowledging it. High MTTA may indicate alert fatigue, staffing gaps or unclear escalation paths.', related: ['On-Call', 'Escalation Policy', 'Mean Time to Detect'] },
  { term: 'Mean Time Between Failures', abbr: 'MTBF', category: 'Fundamentals', definition: 'The average operational time between consecutive failures of a system or component. Used alongside MTTR to assess overall reliability and maintenance needs.', related: ['Mean Time to Recovery', 'Uptime', 'High Availability'] },
  { term: 'On-Call', abbr: null, category: 'Fundamentals', definition: 'A rotation schedule assigning engineers to respond to production alerts and incidents outside normal hours, with defined escalation paths and response-time expectations.', related: ['PagerDuty', 'Escalation Policy', 'Runbook'] },
  { term: 'Runbook', abbr: null, category: 'Fundamentals', definition: 'A documented set of step-by-step procedures for diagnosing and resolving known operational issues, enabling consistent incident response even by engineers unfamiliar with the system.', related: ['Incident Management', 'On-Call', 'Playbook'] },
  { term: 'Root Cause Analysis', abbr: 'RCA', category: 'Fundamentals', definition: 'A structured investigation to identify the underlying cause of an incident rather than just its symptoms, producing actionable fixes that prevent recurrence.', related: ['Postmortem', 'Blameless Postmortem', 'Incident Management'] },
  { term: 'RED Method', abbr: null, category: 'Fundamentals', definition: 'A monitoring framework for request-driven services focusing on three metrics: Rate (requests per second), Errors (failed requests) and Duration (latency distribution).', related: ['Four Golden Signals', 'Golden Metrics', 'Service Level Indicator'] },
  { term: 'USE Method', abbr: null, category: 'Fundamentals', definition: 'A resource-utilization monitoring framework measuring Utilization (percent busy), Saturation (queued work) and Errors for every system resource — CPU, memory, disk and network.', related: ['RED Method', 'Saturation Point', 'CPU Utilization'] },
  { term: 'Four Golden Signals', abbr: null, category: 'Fundamentals', definition: 'Google SRE’s core monitoring signals: Latency, Traffic, Errors and Saturation. Monitoring these four dimensions catches most production problems before users are broadly affected.', related: ['RED Method', 'Golden Metrics', 'Service Level Objective'] },
  { term: 'Burn Rate', abbr: null, category: 'Fundamentals', definition: 'The rate at which an error budget is being consumed relative to the SLO window. A burn rate of 14.4× means the entire monthly budget will be exhausted in two days at the current failure rate.', related: ['Error Budget', 'Service Level Objective', 'Alerting Rule'] },

  // ── Visualization ─────────────────────────────────────────────────────────
  { term: 'Dashboard', abbr: null, category: 'Visualization', definition: 'A visual panel that aggregates metrics, logs and traces into charts, tables and status indicators, giving operators an at-a-glance view of system health and trends.', related: ['Grafana', 'Time Series Chart', 'Golden Metrics'] },
  { term: 'Flame Graph', abbr: null, category: 'Visualization', definition: 'A hierarchical visualization of stack samples where box width represents time spent in each function. Flame graphs quickly reveal hot paths and bottlenecks in CPU profiles.', related: ['Profiler', 'Code Profiling', 'Hot Path'] },
  { term: 'Waterfall Chart', abbr: null, category: 'Visualization', definition: 'A timeline visualization showing the sequential timing of operations within a single request or page load, making it easy to spot slow stages and blocking resources.', related: ['Span Duration', 'First Contentful Paint', 'Time to Interactive'] },
  { term: 'Service Map', abbr: null, category: 'Visualization', definition: 'A real-time graph of services and their dependencies, with edges colored or weighted by traffic volume, latency or error rate to highlight unhealthy relationships.', related: ['Dependency Map', 'Topology Mapping', 'Service Dependency'] },
  { term: 'Sankey Diagram', abbr: null, category: 'Visualization', definition: 'A flow diagram where arrow width is proportional to quantity, commonly used to visualize request routing, traffic distribution or conversion funnel drop-off.', related: ['Conversion Funnel', 'Dependency Map', 'Dashboard'] },
  { term: 'Treemap', abbr: null, category: 'Visualization', definition: 'A nested rectangle visualization where area represents magnitude, useful for showing relative resource consumption, error distribution or cost breakdown across services.', related: ['Heatmap Visualization', 'Dashboard', 'Dependency Map'] },
  { term: 'Time Series Chart', abbr: null, category: 'Visualization', definition: 'A graph plotting a metric’s value against time, the most common observability visualization for spotting trends, anomalies, spikes and seasonal patterns.', related: ['Dashboard', 'Granularity', 'Recording Rule'] },
  { term: 'Dependency Graph', abbr: null, category: 'Visualization', definition: 'A directed graph showing which components depend on which others, used for impact analysis, blast-radius estimation and understanding cascading failure paths.', related: ['Service Map', 'Dependency Map', 'Topology Mapping'] },

  // ── Incident ──────────────────────────────────────────────────────────────
  { term: 'Postmortem', abbr: null, category: 'Incident', definition: 'A written retrospective after a significant incident documenting timeline, root cause, impact, remediation and follow-up actions to prevent recurrence.', related: ['Blameless Postmortem', 'Root Cause Analysis', 'Incident Management'] },
  { term: 'Incident Management', abbr: null, category: 'Incident', definition: 'The end-to-end process of detecting, triaging, responding to, communicating about and learning from production incidents to minimize customer impact.', related: ['Incident Commander', 'Postmortem', 'On-Call'] },
  { term: 'Incident Priority', abbr: null, category: 'Incident', definition: 'A classification indicating how urgently an incident must be addressed, typically based on customer impact, scope and business criticality of the affected service.', related: ['Incident Severity', 'Escalation Policy', 'Major Incident'] },
  { term: 'Incident Severity', abbr: null, category: 'Incident', definition: 'A scale (e.g. SEV1–SEV5) rating the impact magnitude of an incident — from complete outage affecting all users to minor degradation with a workaround.', related: ['Incident Priority', 'Major Incident', 'Customer Impact'] },
  { term: 'Major Incident', abbr: null, category: 'Incident', definition: 'A high-severity incident requiring coordinated response across multiple teams, often with a dedicated incident commander, war room and executive communication.', related: ['Incident Commander', 'War Room', 'Incident Severity'] },
  { term: 'Status Page', abbr: null, category: 'Incident', definition: 'A public or internal page communicating the current operational status of services, planned maintenance and active incidents to customers and stakeholders.', related: ['Incident Management', 'Uptime', 'Customer Impact'] },
  { term: 'Incident Timeline', abbr: null, category: 'Incident', definition: 'A chronological record of events during an incident — detection, escalation, mitigation steps and resolution — used in postmortems and compliance reporting.', related: ['Postmortem', 'Incident Management', 'Root Cause Analysis'] },
  { term: 'Blast Radius', abbr: null, category: 'Incident', definition: 'The scope of impact when a component fails — how many services, users or data are affected. Designing for small blast radius limits cascading failures.', related: ['Fault Domain', 'Bulkhead', 'Dependency Graph'] },
  { term: 'Mitigation', abbr: null, category: 'Incident', definition: 'An immediate action taken during an incident to reduce customer impact — such as rolling back a deployment, disabling a feature or rerouting traffic — without necessarily fixing the root cause.', related: ['Remediation', 'Rollback', 'Incident Management'] },
  { term: 'Remediation', abbr: null, category: 'Incident', definition: 'The permanent fix applied after an incident to address the root cause and prevent recurrence, distinct from short-term mitigation steps.', related: ['Mitigation', 'Root Cause Analysis', 'Postmortem'] },
  { term: 'Containment', abbr: null, category: 'Incident', definition: 'Actions taken to limit the spread or impact of an incident — isolating a compromised host, blocking malicious traffic or quarantining a failing service.', related: ['Mitigation', 'Blast Radius', 'Incident Management'] },
  { term: 'On-Call Rotation', abbr: null, category: 'Incident', definition: 'A scheduled cycle assigning team members to primary and secondary on-call duties, ensuring continuous incident coverage with fair workload distribution.', related: ['On-Call', 'Escalation Policy', 'PagerDuty'] },
  { term: 'Escalation Matrix', abbr: null, category: 'Incident', definition: 'A predefined table mapping incident severity and elapsed time to the roles and teams that must be notified, ensuring timely involvement of the right expertise.', related: ['Escalation Policy', 'Incident Priority', 'On-Call Rotation'] },
  { term: 'Customer Impact', abbr: null, category: 'Incident', definition: 'The measurable effect of an incident on end users — failed transactions, degraded latency, data loss or unavailable features — used to prioritize response.', related: ['Incident Severity', 'Blast Radius', 'Status Page'] },

  // ── Architecture ──────────────────────────────────────────────────────────
  { term: 'Circuit Breaker', abbr: null, category: 'Architecture', definition: 'A resilience pattern that stops calls to a failing downstream service after a threshold of errors, returning a fallback response and periodically testing recovery to prevent cascading failures.', related: ['Bulkhead', 'Retry', 'Graceful Degradation'] },
  { term: 'Hexagonal Architecture', abbr: 'Ports and Adapters', category: 'Architecture', definition: 'An architectural style that isolates business logic at the core and connects to external systems through ports and adapters, making the domain testable and infrastructure-swappable.', related: ['Clean Architecture', 'Loosely Coupled Architecture', 'Domain-Driven Design'] },
  { term: 'Clean Architecture', abbr: null, category: 'Architecture', definition: 'A layered architecture pattern where dependencies point inward toward business rules, keeping frameworks, databases and UI as replaceable outer layers.', related: ['Hexagonal Architecture', 'Domain-Driven Design', 'Microservices Architecture'] },
  { term: 'Domain-Driven Design', abbr: 'DDD', category: 'Architecture', definition: 'A software design approach that models complex systems around business domains and their bounded contexts, using a shared ubiquitous language between developers and domain experts.', related: ['Microservices Architecture', 'Event-Driven Architecture', 'Clean Architecture'] },
  { term: 'Sidecar Pattern', abbr: null, category: 'Architecture', definition: 'A deployment pattern where a helper container runs alongside the main application container in the same pod, handling cross-cutting concerns like logging, proxying or monitoring without modifying app code.', related: ['Service Mesh', 'Sidecar Container', 'Ambassador Pattern'] },
  { term: 'Ambassador Pattern', abbr: null, category: 'Architecture', definition: 'A sidecar proxy that handles outbound communication on behalf of the application — connection pooling, retries, circuit breaking and protocol translation.', related: ['Sidecar Pattern', 'Service Proxy', 'Circuit Breaker'] },
  { term: 'Adapter Pattern', abbr: null, category: 'Architecture', definition: 'A sidecar or wrapper that normalizes heterogeneous interfaces — legacy protocols, varied APIs — into a consistent format the main application expects.', related: ['Sidecar Pattern', 'Service-Oriented Architecture', 'API Gateway'] },
  { term: 'API Composition', abbr: null, category: 'Architecture', definition: 'An architectural pattern where a composite API aggregates responses from multiple backend services into a single client-facing endpoint, reducing chattiness and simplifying client logic.', related: ['API Gateway', 'Microservices Architecture', 'GraphQL'] },
  { term: 'Event-Driven Microservices', abbr: null, category: 'Architecture', definition: 'Microservices that communicate primarily through asynchronous events on a message bus rather than synchronous HTTP calls, enabling loose coupling and independent scaling.', related: ['Event-Driven Architecture', 'Message Queue', 'CQRS'] },

  // ── Service Mesh ──────────────────────────────────────────────────────────
  { term: 'Kiali', abbr: null, category: 'Service Mesh', definition: 'An observability console for Istio service meshes that visualizes traffic topology, validates configuration, shows health metrics and helps debug routing and security policies.', related: ['Istio', 'Service Map', 'Envoy'] },
  { term: 'Consul Connect', abbr: null, category: 'Service Mesh', definition: 'HashiCorp Consul’s service mesh capability providing automatic mTLS, service discovery and L4/L7 traffic management between services via sidecar proxies.', related: ['Service Mesh', 'mTLS', 'Envoy'] },
  { term: 'AWS App Mesh', abbr: null, category: 'Service Mesh', definition: 'A managed AWS service mesh that standardizes communication between microservices using Envoy proxies, with integration into CloudWatch and X-Ray for observability.', related: ['Service Mesh', 'Envoy', 'AWS X-Ray'] },
  { term: 'Context Propagation', abbr: null, category: 'Service Mesh', definition: 'The mechanism by which metadata — trace IDs, baggage, auth tokens — is carried across service boundaries so that distributed operations remain correlated end to end.', related: ['Trace Context', 'Baggage', 'mTLS'] },
  { term: 'East-West Traffic', abbr: null, category: 'Service Mesh', definition: 'Network communication between services within a data center or cluster, as opposed to north-south traffic between clients and the edge. Service meshes primarily secure and observe east-west traffic.', related: ['Service Mesh', 'mTLS', 'Data Plane'] },
  { term: 'Traffic Splitting', abbr: null, category: 'Service Mesh', definition: 'Routing a percentage of requests to different service versions or destinations, enabling canary releases, A/B testing and failover without changing client configuration.', related: ['Canary Deployment', 'Progressive Delivery', 'Istio'] },

  // ── Infrastructure ────────────────────────────────────────────────────────
  { term: 'Memory Utilization', abbr: null, category: 'Infrastructure', definition: 'The percentage of available memory currently in use by a host or container. Sustained high utilization risks OOM kills and performance degradation.', related: ['CPU Utilization', 'OOM Kill', 'USE Method'] },
  { term: 'Network Throughput', abbr: null, category: 'Infrastructure', definition: 'The rate of data transferred over a network interface, measured in bits or bytes per second. Throughput limits can bottleneck distributed systems and data pipelines.', related: ['Bandwidth', 'IOPS', 'Saturation Point'] },
  { term: 'Swap Space', abbr: null, category: 'Infrastructure', definition: 'Disk space used as overflow when physical memory is exhausted. Heavy swapping causes severe latency and is a sign of memory pressure or undersized instances.', related: ['Memory Utilization', 'Memory Pressure', 'OOM Kill'] },
  { term: 'Memory Pressure', abbr: null, category: 'Infrastructure', definition: 'A condition where a system is running low on available memory, triggering the kernel or runtime to reclaim pages, throttle allocations or evict caches.', related: ['Memory Utilization', 'Swap Space', 'OOM Kill'] },
  { term: 'I/O Wait', abbr: null, category: 'Infrastructure', definition: 'The percentage of CPU time spent waiting for disk or storage I/O to complete. High I/O wait indicates storage bottlenecks rather than CPU saturation.', related: ['Disk Latency', 'IOPS', 'USE Method'] },
  { term: 'Disk Throughput', abbr: null, category: 'Infrastructure', definition: 'The rate at which data can be read from or written to a storage device, limited by media type (HDD vs SSD vs NVMe), interface and queue depth.', related: ['IOPS', 'Disk Latency', 'NVMe'] },
  { term: 'Block Device', abbr: null, category: 'Infrastructure', definition: 'A storage device accessed in fixed-size blocks — hard drives, SSDs and volume attachments — as opposed to stream-oriented character devices.', related: ['Volume', 'NVMe', 'Filesystem'] },
  { term: 'OOM Kill', abbr: 'Out-of-Memory Kill', category: 'Infrastructure', definition: 'When the Linux kernel or container runtime terminates a process that exceeds its memory limit to protect the host from total memory exhaustion.', related: ['Memory Utilization', 'Resource Limit', 'cgroup'] },
  { term: 'CPU Throttling', abbr: null, category: 'Infrastructure', definition: 'Limiting a container’s CPU usage when it exceeds its allocated quota, causing increased latency without crashing the process. A common cause of unexplained slowdowns.', related: ['CPU Utilization', 'Resource Limit', 'cgroup'] },
  { term: 'Resource Contention', abbr: null, category: 'Infrastructure', definition: 'When multiple workloads compete for the same finite resource — CPU, memory, disk I/O or network bandwidth — degrading performance for all parties involved.', related: ['Noisy Neighbor', 'Saturation Point', 'USE Method'] },

  // ── APM ───────────────────────────────────────────────────────────────────
  { term: 'Thread Dump', abbr: null, category: 'APM', definition: 'A snapshot of all threads in a running JVM or runtime process, showing stack traces and lock states. Essential for diagnosing deadlocks, thread starvation and hung requests.', related: ['Deadlock', 'Stack Trace', 'Heap Dump'] },
  { term: 'Heap Dump', abbr: null, category: 'APM', definition: 'A capture of all objects in a runtime’s memory heap at a point in time, used to analyze memory leaks, object retention and garbage-collection pressure.', related: ['Memory Leak', 'Garbage Collection', 'Thread Dump'] },
  { term: 'Code Profiling', abbr: null, category: 'APM', definition: 'Measuring where an application spends its execution time — by function, line or call path — to identify performance bottlenecks and optimization targets.', related: ['Profiler', 'Flame Graph', 'CPU Profiling'] },
  { term: 'CPU Profiling', abbr: null, category: 'APM', definition: 'Sampling or instrumenting a process to determine which functions consume the most CPU time, typically visualized as flame graphs or call trees.', related: ['Code Profiling', 'Flame Graph', 'Hot Path'] },
  { term: 'Memory Profiling', abbr: null, category: 'APM', definition: 'Tracking memory allocations and object lifetimes to find leaks, excessive retention and inefficient data structures.', related: ['Heap Dump', 'Memory Leak', 'Allocation Profiling'] },
  { term: 'Allocation Profiling', abbr: null, category: 'APM', definition: 'Recording where and how frequently objects are allocated in memory, helping pinpoint code paths that create excessive garbage-collection pressure.', related: ['Memory Profiling', 'Garbage Collection', 'Heap Dump'] },
  { term: 'Call Tree', abbr: null, category: 'APM', definition: 'A hierarchical view of function calls during execution, showing parent-child relationships and cumulative time spent in each branch of the call stack.', related: ['Call Graph', 'Flame Graph', 'Stack Trace'] },
  { term: 'Application Performance Monitoring', abbr: 'APM', category: 'APM', definition: 'End-to-end monitoring of application health — response times, error rates, throughput and resource usage — with code-level visibility into slow transactions and failures.', related: ['Profiler', 'Distributed Tracing', 'Service Health'] },
  { term: 'Business Transaction Monitoring', abbr: 'BTM', category: 'APM', definition: 'Tracking the performance and success rate of multi-step business workflows — checkout, login, payment — across distributed services as a single logical unit.', related: ['Application Performance Monitoring', 'Critical User Journey', 'Distributed Tracing'] },
  { term: 'N+1 Query Problem', abbr: null, category: 'APM', definition: 'A performance anti-pattern where an application executes one query to fetch a list and then N additional queries for each item’s related data, causing severe database load.', related: ['Slow Transaction', 'Response Time', 'External Call'] },

  // ── Data Formats ────────────────────────────────────────────────────────────
  { term: 'NDJSON', abbr: 'Newline-Delimited JSON', category: 'Data Formats', definition: 'A format where each line is a separate, valid JSON object. Widely used for log streaming, bulk data export and append-only pipelines because it is easy to parse line by line.', related: ['JSON', 'JSON Lines', 'Log Shipper'] },
  { term: 'JSON Lines', abbr: 'JSONL', category: 'Data Formats', definition: 'A text format with one JSON value per line, functionally equivalent to NDJSON. Common in machine-learning datasets, log files and streaming ETL.', related: ['JSON', 'NDJSON', 'Parquet'] },
  { term: 'MessagePack', abbr: null, category: 'Data Formats', definition: 'A binary serialization format that is more compact and faster to parse than JSON while preserving the same data types, popular for inter-service communication and caching.', related: ['JSON', 'CBOR', 'Protocol Buffers'] },
  { term: 'CBOR', abbr: 'Concise Binary Object Representation', category: 'Data Formats', definition: 'An IETF-standard binary data format similar to JSON but more compact, self-describing and suitable for constrained environments like IoT devices.', related: ['MessagePack', 'JSON', 'Encoding'] },
  { term: 'TOML', abbr: 'Tom\'s Obvious Minimal Language', category: 'Data Formats', definition: 'A human-readable configuration file format with explicit types and clear section hierarchy, used by tools like Cargo, PyProject and many cloud-native projects.', related: ['YAML', 'INI', 'Configuration as Code'] },
  { term: 'INI', abbr: null, category: 'Data Formats', definition: 'A simple text configuration format organized into sections with key-value pairs, common in legacy applications and Windows system settings.', related: ['TOML', 'YAML', 'Configuration Management'] },
  { term: 'Protocol Buffer Schema', abbr: 'Protobuf Schema', category: 'Data Formats', definition: 'A language-neutral interface definition (.proto file) that specifies message structures and RPC services, compiled into efficient serialization code for multiple languages.', related: ['Protocol Buffers', 'gRPC', 'Schema Registry'] },
  { term: 'ORC', abbr: 'Optimized Row Columnar', category: 'Data Formats', definition: 'A columnar storage format optimized for Hive and Hadoop workloads, offering efficient compression and fast reads for analytic queries over large datasets.', related: ['Parquet', 'Avro', 'Compression'] },

  // ── IT Operations ─────────────────────────────────────────────────────────
  { term: 'ChatOps', abbr: null, category: 'IT Operations', definition: 'Running operational workflows through chat platforms — triggering deploys, querying metrics, acknowledging alerts and coordinating incidents from Slack or Teams channels.', related: ['Incident Management', 'Runbook', 'On-Call'] },
  { term: 'Change Advisory Board', abbr: 'CAB', category: 'IT Operations', definition: 'A governance body that reviews, approves or rejects proposed changes to production systems, balancing agility with risk management per ITIL practices.', related: ['Change Management', 'ITIL', 'Production Readiness'] },
  { term: 'Operational Readiness', abbr: null, category: 'IT Operations', definition: 'The state of being prepared to run a service in production — covering monitoring, alerting, runbooks, on-call coverage, capacity and rollback plans.', related: ['Production Readiness', 'Launch Checklist', 'Runbook'] },
  { term: 'Production Readiness', abbr: null, category: 'IT Operations', definition: 'A review process verifying that a service meets reliability, security, observability and operational standards before it is allowed to serve production traffic.', related: ['Operational Readiness', 'Service Level Objective', 'Health Check'] },
  { term: 'Service Request', abbr: null, category: 'IT Operations', definition: 'A formal user request for a standard IT service — access provisioning, hardware, software installation — handled through the service desk per ITIL.', related: ['Service Desk', 'Ticket', 'ITSM'] },
  { term: 'Change Request', abbr: null, category: 'IT Operations', definition: 'A documented proposal to modify production infrastructure or applications, requiring assessment, approval and scheduling through change management processes.', related: ['Change Management', 'Change Advisory Board', 'Configuration Management'] },
  { term: 'Incident Record', abbr: null, category: 'IT Operations', definition: 'A formal ITSM ticket documenting an unplanned service interruption, including impact, timeline, resolution steps and links to the postmortem.', related: ['Incident Management', 'Ticket', 'Problem Management'] },
  { term: 'Knowledge Base', abbr: 'KB', category: 'IT Operations', definition: 'A curated repository of articles, runbooks and FAQs that support self-service resolution and consistent incident handling across the operations team.', related: ['Runbook', 'Service Desk', 'Documentation'] },
  { term: 'Release Management', abbr: null, category: 'IT Operations', definition: 'The ITIL process of planning, scheduling and controlling software releases into production, coordinating changes across teams and environments.', related: ['Change Management', 'Continuous Deployment', 'Rollback'] },

  // ── Containers ────────────────────────────────────────────────────────────
  { term: 'CRI-O', abbr: null, category: 'Containers', definition: 'A lightweight container runtime purpose-built for Kubernetes via the Container Runtime Interface, focused on running OCI-compliant images without extra daemon overhead.', related: ['containerd', 'OCI', 'Container Runtime'] },
  { term: 'Podman', abbr: null, category: 'Containers', definition: 'A daemonless container engine that runs OCI containers as regular user processes, supporting rootless operation and Kubernetes-compatible pod semantics.', related: ['Docker', 'Rootless Container', 'OCI'] },
  { term: 'Buildah', abbr: null, category: 'Containers', definition: 'A tool for building OCI container images from scratch or Dockerfiles without requiring a running container daemon, enabling flexible CI/CD image pipelines.', related: ['Dockerfile', 'OCI', 'Multi-Stage Build'] },
  { term: 'Skopeo', abbr: null, category: 'Containers', definition: 'A command-line utility for inspecting, copying and signing container images across registries and storage backends without a local daemon.', related: ['Container Registry', 'Container Image', 'OCI'] },
  { term: 'Multi-Stage Build', abbr: null, category: 'Containers', definition: 'A Dockerfile technique using multiple FROM stages to separate build-time dependencies from the final runtime image, producing smaller and more secure images.', related: ['Dockerfile', 'Distroless Image', 'Container Image'] },
  { term: 'Distroless Image', abbr: null, category: 'Containers', definition: 'A minimal container image containing only the application and its runtime dependencies — no shell, package manager or OS utilities — reducing attack surface.', related: ['Multi-Stage Build', 'Container Security', 'Scratch Image'] },
  { term: 'Scratch Image', abbr: null, category: 'Containers', definition: 'An empty base image with no filesystem layers, used for statically compiled binaries that need no OS libraries — the smallest possible container.', related: ['Distroless Image', 'Base Image', 'Container Image'] },
  { term: 'Base Image', abbr: null, category: 'Containers', definition: 'The starting layer in a container image build, typically an OS distribution or language runtime that subsequent Dockerfile instructions extend.', related: ['Container Image', 'Layer (Image)', 'Multi-Stage Build'] },
  { term: 'Image Tag', abbr: null, category: 'Containers', definition: 'A mutable label (e.g. latest, v1.2.3) applied to a container image in a registry to identify a specific build. Tags can be overwritten, unlike immutable digests.', related: ['Image Digest', 'Container Registry', 'Container Image'] },
  { term: 'Image Digest', abbr: null, category: 'Containers', definition: 'A cryptographic hash (SHA-256) uniquely identifying an immutable container image content. Referencing by digest guarantees the exact same image is pulled every time.', related: ['Image Tag', 'Container Registry', 'Software Supply Chain'] },
  { term: 'Rootless Container', abbr: null, category: 'Containers', definition: 'A container running without root privileges on the host, using user namespaces to map container root to an unprivileged host user, improving security isolation.', related: ['Podman', 'Namespace (Linux)', 'Container Security'] },
  { term: 'Resource Limit', abbr: null, category: 'Containers', definition: 'The maximum CPU, memory or storage a container is allowed to consume, enforced by the runtime via cgroups. Exceeding memory limits triggers OOM kill.', related: ['Resource Request', 'cgroup', 'OOM Kill'] },
  { term: 'Resource Request', abbr: null, category: 'Containers', definition: 'The guaranteed minimum resources a scheduler reserves for a container on a node. Requests drive placement decisions; limits cap maximum usage.', related: ['Resource Limit', 'Bin Packing', 'Kubernetes'] },

  // ── Logging ───────────────────────────────────────────────────────────────
  { term: 'Structured Logging', abbr: null, category: 'Logging', definition: 'Writing log entries as machine-parseable key-value pairs (usually JSON) rather than free-form text, enabling reliable filtering, aggregation and correlation in log platforms.', related: ['JSON', 'Log Parser', 'Centralized Logging'] },
  { term: 'Log Aggregation', abbr: null, category: 'Logging', definition: 'Collecting log streams from many hosts, containers and services into a centralized store for search, analysis, alerting and long-term retention.', related: ['Centralized Logging', 'Log Shipper', 'Loki'] },
  { term: 'Correlation ID', abbr: null, category: 'Logging', definition: 'A unique identifier propagated across all log entries and service calls belonging to a single request, enabling end-to-end tracing through distributed log data.', related: ['Trace Context', 'Structured Logging', 'Distributed Tracing'] },
  { term: 'Log Level', abbr: null, category: 'Logging', definition: 'A severity classification for log entries — DEBUG, INFO, WARN, ERROR, FATAL — controlling which messages are emitted and stored based on configured thresholds.', related: ['Application Log', 'Structured Logging', 'Log Sampling'] },
  { term: 'Log Retention', abbr: null, category: 'Logging', definition: 'The policy governing how long log data is kept in hot, warm and cold storage before deletion, balancing compliance requirements against storage cost.', related: ['Log Rotation', 'Data Tiering', 'Centralized Logging'] },
  { term: 'Log Index', abbr: null, category: 'Logging', definition: 'A searchable data structure built over log fields to accelerate queries. High-cardinality indexes improve search speed but increase storage and ingestion cost.', related: ['Faceted Search', 'Full-Text Search', 'Log Parser'] },
  { term: 'Log Parser', abbr: null, category: 'Logging', definition: 'A rule or pipeline stage that extracts structured fields from raw log lines — timestamps, severity, request IDs — making unstructured text queryable.', related: ['Structured Logging', 'Log Pattern', 'Log Enrichment'] },
  { term: 'Log Enrichment', abbr: null, category: 'Logging', definition: 'Adding contextual metadata to log entries at collection time — host name, pod name, environment, trace ID — so downstream analysis has more dimensions to filter on.', related: ['Structured Logging', 'Correlation ID', 'Log Shipper'] },
  { term: 'Log Correlation', abbr: null, category: 'Logging', definition: 'Linking related log entries across services and time using shared identifiers, temporal proximity or topology to reconstruct the story of a request or incident.', related: ['Correlation ID', 'Topology-Based Correlation', 'Distributed Tracing'] },
  { term: 'Log Volume', abbr: null, category: 'Logging', definition: 'The total quantity of log data ingested over a period, a primary driver of observability cost. Log sampling and level tuning are common strategies to control volume.', related: ['Log Sampling', 'Observability Cost', 'Log Retention'] },

  // ── Tracing ───────────────────────────────────────────────────────────────
  { term: 'Distributed Tracing', abbr: null, category: 'Tracing', definition: 'Tracking a single request as it flows through multiple services, recording timing and metadata at each hop to diagnose latency, errors and dependency issues.', related: ['Span', 'Trace ID', 'OpenTelemetry'] },
  { term: 'Span', abbr: null, category: 'Tracing', definition: 'A single timed operation within a trace — an HTTP call, database query or function execution — with a name, start/end timestamps, attributes and optional events.', related: ['Child Span', 'Span Duration', 'Distributed Tracing'] },
  { term: 'Trace ID', abbr: null, category: 'Tracing', definition: 'A globally unique identifier assigned to an entire distributed trace, shared across all spans so they can be reassembled into a complete request timeline.', related: ['Span ID', 'Trace Context', 'Correlation ID'] },
  { term: 'Parent Span', abbr: null, category: 'Tracing', definition: 'The span that initiated the current span in a trace tree. Parent-child relationships reveal call hierarchy and where time is spent in nested operations.', related: ['Child Span', 'Span', 'Critical Path'] },
  { term: 'Trace Propagation', abbr: null, category: 'Tracing', definition: 'Passing trace context — trace ID, span ID, sampling flags — across process and network boundaries via HTTP headers or message metadata so spans stay linked.', related: ['Trace Context', 'B3 Propagation', 'Context Propagation'] },
  { term: 'W3C Trace Context', abbr: null, category: 'Tracing', definition: 'The W3C standard defining traceparent and tracestate HTTP headers for interoperable trace context propagation across vendors and languages.', related: ['Trace Context', 'B3 Propagation', 'OpenTelemetry'] },
  { term: 'Baggage', abbr: null, category: 'Tracing', definition: 'Key-value pairs propagated alongside trace context across service boundaries, carrying business context like user ID or tenant without storing it in every span attribute.', related: ['Trace Context', 'Context Propagation', 'Span Attributes'] },
  { term: 'Head-Based Sampling', abbr: null, category: 'Tracing', definition: 'A sampling decision made at the start of a trace — typically at the edge — that determines whether all downstream spans are recorded. Simple but can miss rare errors deep in the call chain.', related: ['Tail-Based Sampling', 'Trace Sampling Rate', 'Sampling Decision'] },
  { term: 'Tail-Based Sampling', abbr: null, category: 'Tracing', definition: 'Deferring the sampling decision until a trace completes, allowing retention of traces with errors or high latency while discarding routine successful requests.', related: ['Head-Based Sampling', 'Trace Sampling Rate', 'Sampling Decision'] },
  { term: 'Span Link', abbr: null, category: 'Tracing', definition: 'A reference connecting spans from different traces — such as a consumer span linking back to the producer span in an async message flow.', related: ['Span', 'Trace ID', 'Message Queue'] },
  { term: 'Span Status', abbr: null, category: 'Tracing', definition: 'An OK/ERROR indicator on a span signaling whether the operation succeeded, complementing HTTP status codes and exception events for error analysis.', related: ['Span', 'Span Events', 'Error Tracking'] },

  // ── Metrics ───────────────────────────────────────────────────────────────
  { term: 'Histogram', abbr: null, category: 'Metrics', definition: 'A metric type that samples observations — typically latencies or sizes — and counts them in configurable buckets, enabling percentile calculations like p50, p95 and p99.', related: ['Bucket', 'Quantile', 'Summary'] },
  { term: 'Gauge', abbr: null, category: 'Metrics', definition: 'A metric type representing a single numerical value that can arbitrarily go up or down, such as current memory usage, queue depth or active connections.', related: ['Counter', 'StatsD', 'Data Point'] },
  { term: 'Counter', abbr: null, category: 'Metrics', definition: 'A monotonically increasing metric type that only goes up (or resets to zero), used for counting events like requests served, errors encountered or bytes sent.', related: ['Gauge', 'Monotonic', 'Counter Reset'] },
  { term: 'Summary', abbr: null, category: 'Metrics', definition: 'A metric type that calculates quantiles over a sliding time window client-side, providing pre-computed percentiles without server-side histogram bucketing.', related: ['Histogram', 'Quantile', 'Data Point'] },
  { term: 'Cardinality', abbr: null, category: 'Metrics', definition: 'The number of unique time series produced by a metric, driven by the combination of metric name and label values. High cardinality inflates storage cost and query latency.', related: ['Metric Label', 'Cardinality Explosion', 'Cardinality (Data)'] },
  { term: 'Error Rate', abbr: null, category: 'Metrics', definition: 'The proportion of requests or operations that fail, typically expressed as a percentage or ratio. A core SLI for most services and a key input to error budgets.', related: ['Service Level Indicator', 'RED Method', 'Burn Rate'] },
  { term: 'SLO Burn Rate', abbr: null, category: 'Metrics', definition: 'A metric expressing how fast the error budget is being consumed relative to the SLO window, used to trigger multi-window alerting before the budget is fully exhausted.', related: ['Burn Rate', 'Error Budget', 'Service Level Objective'] },
  { term: 'Scrape Target', abbr: null, category: 'Metrics', definition: 'An endpoint from which a metrics collector like Prometheus periodically pulls (scrapes) metric data, identified by host, port and metrics path.', related: ['Scrape Interval', 'Prometheus Exporter', 'Pull vs Push'] },

  // ── Cloud Native ──────────────────────────────────────────────────────────
  { term: 'Serverless', abbr: null, category: 'Cloud Native', definition: 'A cloud execution model where the provider manages infrastructure and scaling automatically; developers deploy functions or containers billed only for actual usage time.', related: ['Function as a Service', 'Cold Start (Runtime)', 'Immutable Infrastructure'] },
  { term: 'Chaos Engineering', abbr: null, category: 'Cloud Native', definition: 'The practice of deliberately injecting failures — killed pods, network latency, resource exhaustion — into production to validate resilience before real outages occur.', related: ['Fault Injection', 'Game Day', 'Fault Tolerance'] },
  { term: 'Operator Pattern', abbr: null, category: 'Cloud Native', definition: 'A Kubernetes design pattern where a custom controller encodes operational domain knowledge — deploying, scaling, backing up — for complex stateful applications.', related: ['Custom Resource Definition', 'Controller Pattern', 'Reconciliation'] },
  { term: 'Controller Pattern', abbr: null, category: 'Cloud Native', definition: 'A control loop that continuously compares desired state (declared in configuration) with actual state and takes corrective actions to converge them.', related: ['Reconciliation', 'Operator Pattern', 'Desired State'] },
  { term: 'GitOps Workflow', abbr: null, category: 'Cloud Native', definition: 'An operational model where the desired state of infrastructure and applications is stored in Git and an automated agent reconciles the live environment to match.', related: ['GitOps', 'Reconciliation', 'Argo CD'] },
  { term: 'Progressive Rollout', abbr: null, category: 'Cloud Native', definition: 'Gradually shifting traffic to a new version while monitoring error rates and latency, automatically pausing or rolling back if SLOs are breached.', related: ['Canary Deployment', 'Progressive Delivery', 'Traffic Splitting'] },
  { term: 'Workload Identity', abbr: null, category: 'Cloud Native', definition: 'A mechanism allowing workloads in Kubernetes to authenticate to cloud services using their pod identity rather than long-lived credentials, improving security posture.', related: ['Service Account', 'Least Privilege', 'Secrets Management'] },
  { term: 'Policy Engine', abbr: null, category: 'Cloud Native', definition: 'Software that evaluates policies against Kubernetes resources or cloud configurations at admission or audit time, enforcing security and compliance guardrails.', related: ['Policy as Code', 'Admission Controller', 'OPA'] },

  // ── Digital Experience ────────────────────────────────────────────────────
  { term: 'Core Web Vitals', abbr: null, category: 'Digital Experience', definition: 'Google’s three key user-experience metrics: Largest Contentful Paint (loading), Interaction to Next Paint (interactivity) and Cumulative Layout Shift (visual stability).', related: ['Largest Contentful Paint', 'Interaction to Next Paint', 'Cumulative Layout Shift'] },
  { term: 'Real User Monitoring', abbr: 'RUM', category: 'Digital Experience', definition: 'Collecting performance and behavior data from actual user browsers and devices in production, as opposed to synthetic tests run from fixed locations.', related: ['Synthetic Transaction', 'User Session', 'Digital Experience Monitoring'] },
  { term: 'Apdex', abbr: 'Application Performance Index', category: 'Digital Experience', definition: 'A standardized score (0–1) classifying response times as satisfied, tolerating or frustrated based on a threshold T, giving a single number for user-perceived performance.', related: ['Response Time', 'Service Level Objective', 'User Experience'] },
  { term: 'Session Replay', abbr: null, category: 'Digital Experience', definition: 'Recording and playback of a user’s browser session — clicks, scrolls, navigation — to reproduce bugs and understand frustration signals that metrics alone cannot explain.', related: ['Frustration Signal', 'Rage Click', 'User Session'] },
  { term: 'Speed Index', abbr: null, category: 'Digital Experience', definition: 'A page-load metric measuring how quickly visible content is painted during load, capturing perceived speed better than a single onload timestamp.', related: ['First Contentful Paint', 'Largest Contentful Paint', 'Core Web Vitals'] },
  { term: 'Critical User Journey', abbr: null, category: 'Digital Experience', definition: 'An end-to-end path that is essential to business value — signup, purchase, login — monitored as a single flow with SLOs on success rate and latency.', related: ['Conversion Funnel', 'Business Transaction Monitoring', 'Synthetic Transaction'] },
  { term: 'User Journey', abbr: null, category: 'Digital Experience', definition: 'The sequence of steps a user takes to accomplish a goal within an application, used to map monitoring coverage and identify drop-off points.', related: ['Critical User Journey', 'Conversion Funnel', 'Page View'] },
  { term: 'Conversion Rate', abbr: null, category: 'Digital Experience', definition: 'The percentage of users who complete a desired action — purchase, signup, download — out of the total who started the funnel, a primary business metric.', related: ['Conversion Funnel', 'Bounce Rate', 'User Session'] },
  { term: 'Synthetic Monitoring', abbr: null, category: 'Digital Experience', definition: 'Running scripted tests from controlled locations at regular intervals to verify availability and performance, detecting issues before real users are affected.', related: ['Synthetic Transaction', 'Synthetic Location', 'Uptime Monitoring'] },
  { term: 'Digital Experience Monitoring', abbr: 'DEM', category: 'Digital Experience', definition: 'Holistic monitoring of how end users perceive application performance and reliability, combining RUM, synthetic tests and session analytics.', related: ['Real User Monitoring', 'User Experience', 'Apdex'] },

  // ── Standards & Tools (missing core observability platforms) ──────────────
  { term: 'Prometheus', abbr: null, category: 'Standards & Tools', definition: 'An open-source metrics collection and alerting system using a pull-based scrape model, PromQL query language and dimensional time-series labels. A CNCF graduated project and the de facto Kubernetes monitoring standard.', related: ['Alertmanager', 'Recording Rule', 'OpenMetrics'] },
  { term: 'Grafana', abbr: null, category: 'Standards & Tools', definition: 'An open-source visualization and dashboarding platform that queries metrics, logs and traces from many backends — Prometheus, Loki, Tempo, Elasticsearch — in a unified UI.', related: ['Grafana Cloud', 'Dashboard', 'Loki'] },
  { term: 'OpenTelemetry', abbr: 'OTel', category: 'Standards & Tools', definition: 'A CNCF observability framework providing vendor-neutral APIs, SDKs and collectors for generating and exporting metrics, logs and traces, unifying OpenTracing and OpenCensus.', related: ['OpenTracing', 'OpenCensus', 'Semantic Conventions'] },
  { term: 'OpenSearch', abbr: null, category: 'Standards & Tools', definition: 'An open-source search and analytics engine forked from Elasticsearch, used for log analytics, full-text search and observability dashboards via OpenSearch Dashboards.', related: ['Elasticsearch', 'Kibana', 'Log Aggregation'] },
  { term: 'Pulumi', abbr: null, category: 'Standards & Tools', definition: 'An infrastructure-as-code platform that lets teams define cloud resources using general-purpose programming languages (TypeScript, Python, Go) with state management and drift detection.', related: ['Terraform', 'Infrastructure as Code', 'Provisioning'] },
  { term: 'Sigstore', abbr: null, category: 'Standards & Tools', definition: 'An open-source project providing free, transparent code signing and verification for software artifacts, strengthening supply-chain security for container images and binaries.', related: ['SBOM', 'Software Supply Chain', 'Provenance'] },

  // ── AIOps (supplement) ────────────────────────────────────────────────────
  { term: 'Alert Fatigue', abbr: null, category: 'AIOps', definition: 'The desensitization of on-call engineers caused by excessive, low-signal or duplicate alerts, leading to slower response times and missed critical incidents.', related: ['Alert Suppression', 'Alert Deduplication', 'On-Call'] },
  { term: 'Alert Deduplication', abbr: null, category: 'AIOps', definition: 'Grouping or suppressing redundant alerts that describe the same underlying problem, reducing noise and helping engineers focus on distinct issues.', related: ['Alert Grouping', 'Alert Fatigue', 'Topology-Based Correlation'] },
  { term: 'Automated Root Cause Analysis', abbr: 'ARCA', category: 'AIOps', definition: 'Using ML and topology-aware correlation to automatically narrow incident causes — surfacing the most likely failing service, deployment or dependency without manual log diving.', related: ['Root Cause Analysis', 'Topology-Based Correlation', 'Event Correlation'] },
  { term: 'Event Correlation', abbr: null, category: 'AIOps', definition: 'Analyzing streams of alerts and events to identify which ones share a common root cause, collapsing dozens of symptomatic alerts into a single actionable incident.', related: ['Topology-Based Correlation', 'Alert Deduplication', 'Root Cause Analysis'] },
  { term: 'Noise Reduction', abbr: null, category: 'AIOps', definition: 'Techniques — deduplication, suppression, clustering and priority scoring — that filter low-value alerts so on-call engineers see fewer, higher-signal notifications.', related: ['Alert Fatigue', 'Alert Deduplication', 'Signal-to-Noise Ratio'] },

  // ── Batch 3: 140+ terms across all categories ───────────────────────────

  // AI/ML
  { term: 'Speculative Decoding', abbr: null, category: 'AI/ML', definition: 'An inference optimization where a smaller draft model proposes multiple tokens and a larger model verifies them in parallel, dramatically reducing latency for autoregressive generation.', related: ['Inference', 'Large Language Model', 'vLLM'] },
  { term: 'KV Cache', abbr: 'Key-Value Cache', category: 'AI/ML', definition: 'Stored key and value tensors from prior attention computations, reused during autoregressive decoding so the model does not reprocess the entire prompt for every new token.', related: ['Transformer', 'Inference', 'Context Window'] },
  { term: 'Grouped Query Attention', abbr: 'GQA', category: 'AI/ML', definition: 'An attention variant that shares key-value heads across query heads, cutting KV-cache memory use while retaining most of the quality of multi-head attention in large models.', related: ['Multi-Query Attention', 'Transformer', 'KV Cache'] },
  { term: 'Multi-Query Attention', abbr: 'MQA', category: 'AI/ML', definition: 'An attention mechanism where all query heads share a single set of key and value heads, reducing memory bandwidth during inference at some cost to model expressiveness.', related: ['Grouped Query Attention', 'KV Cache', 'Transformer'] },
  { term: 'Rotary Position Embedding', abbr: 'RoPE', category: 'AI/ML', definition: 'A position-encoding method that rotates query and key vectors by an angle proportional to token position, giving transformers relative position awareness and good length extrapolation.', related: ['Positional Encoding', 'Transformer', 'Context Window'] },
  { term: 'Sliding Window Attention', abbr: null, category: 'AI/ML', definition: 'An attention pattern where each token only attends to a fixed-size local window of neighbors, reducing the quadratic cost of full attention for very long sequences.', related: ['Self-Attention', 'Transformer', 'Context Window'] },
  { term: 'vLLM', abbr: null, category: 'AI/ML', definition: 'A high-throughput LLM inference engine using PagedAttention to manage KV-cache memory efficiently, enabling large concurrent request batches on a single GPU.', related: ['KV Cache', 'Inference', 'Speculative Decoding'] },
  { term: 'LangChain', abbr: null, category: 'AI/ML', definition: 'A framework for building LLM applications that chains together prompts, retrievers, tools and memory modules, standardizing the plumbing for RAG and agent workflows.', related: ['Retrieval-Augmented Generation', 'AI Agent', 'LlamaIndex'] },
  { term: 'LlamaIndex', abbr: null, category: 'AI/ML', definition: 'A data framework for connecting LLMs to external data sources — documents, databases, APIs — via indexing, retrieval and query pipelines for RAG applications.', related: ['Retrieval-Augmented Generation', 'Vector Database', 'LangChain'] },
  { term: 'Hybrid Search', abbr: null, category: 'AI/ML', definition: 'Combining keyword-based retrieval (BM25) with dense vector search and merging results, capturing both exact term matches and semantic similarity.', related: ['Semantic Search', 'BM25', 'Reranking'] },
  { term: 'Reranking', abbr: null, category: 'AI/ML', definition: 'A second-pass scoring step that re-orders retrieved documents using a cross-encoder or LLM judge for higher precision than initial retrieval alone.', related: ['Retrieval-Augmented Generation', 'Hybrid Search', 'Cross-Encoder'] },
  { term: 'BM25', abbr: 'Best Matching 25', category: 'AI/ML', definition: 'A probabilistic ranking function for keyword search that scores documents by term frequency and inverse document frequency with length normalization.', related: ['Hybrid Search', 'Semantic Search', 'Sparse Retrieval'] },
  { term: 'Chinchilla Optimal', abbr: null, category: 'AI/ML', definition: 'The compute-optimal balance between model size and training tokens identified by the Chinchilla paper — smaller models trained on more data often outperform larger under-trained ones.', related: ['Scaling Law', 'Pretraining', 'Foundation Model'] },
  { term: 'Emergent Ability', abbr: null, category: 'AI/ML', definition: 'A capability that appears in large language models only above a certain scale threshold — such as chain-of-thought reasoning or instruction following — not present in smaller models.', related: ['Large Language Model', 'Chain-of-Thought', 'Scaling Law'] },

  // AIOps
  { term: 'Change Correlation', abbr: null, category: 'AIOps', definition: 'Linking production anomalies to recent deployments, config changes or feature flags by correlating alert timestamps with change events in the CI/CD pipeline.', related: ['Change Event', 'Event Correlation', 'Deployment Frequency'] },
  { term: 'Drift Detection', abbr: null, category: 'AIOps', definition: 'Monitoring whether live data or model behavior deviates from its training or baseline distribution, signaling that predictions or alerts may no longer be reliable.', related: ['Model Monitoring', 'Baseline Deviation', 'Anomaly Score'] },
  { term: 'Incident Prediction', abbr: null, category: 'AIOps', definition: 'Using historical incident data and leading-indicator metrics to forecast likely outages before they occur, enabling proactive mitigation.', related: ['Predictive Alerting', 'Capacity Forecast', 'Anomaly Score'] },
  { term: 'Auto-Remediation', abbr: null, category: 'AIOps', definition: 'Automated actions triggered by detected issues — restarting pods, scaling replicas, clearing caches — that resolve common failures without human intervention.', related: ['Remediation Action', 'Self-Healing System', 'Runbook Automation'] },
  { term: 'Self-Healing System', abbr: null, category: 'AIOps', definition: 'An infrastructure or application setup that detects failures and automatically applies corrective actions — failover, restart, rollback — to restore healthy state.', related: ['Auto-Remediation', 'Self Healing', 'Health Check'] },

  // APM
  { term: 'Continuous Profiling', abbr: null, category: 'APM', definition: 'Always-on, low-overhead CPU and memory profiling in production that captures flame graphs and hotspot data without manual trigger or significant performance impact.', related: ['Profiler', 'Flame Graph', 'Code Profiling'] },
  { term: 'JVM Metrics', abbr: null, category: 'APM', definition: 'Runtime measurements from the Java Virtual Machine — heap usage, GC pauses, thread counts, class loading — essential for diagnosing Java and Kotlin application performance.', related: ['Garbage Collection', 'Heap Dump', 'GC Pause'] },
  { term: 'P99 Latency', abbr: null, category: 'APM', definition: 'The latency below which 99% of requests complete; the tail metric that reveals worst-case user experience far better than averages.', related: ['Percentile Latency', 'Response Time', 'Service Level Indicator'] },
  { term: 'SQL Query Analysis', abbr: null, category: 'APM', definition: 'Examining database query execution plans, durations and frequencies within APM traces to find slow queries, missing indexes and N+1 patterns.', related: ['N+1 Query Problem', 'Slow Transaction', 'External Call'] },
  { term: 'Code Hotspot', abbr: null, category: 'APM', definition: 'A function or method that consumes a disproportionate share of CPU or wall-clock time during profiling, indicating the primary optimization target.', related: ['Flame Graph', 'Code Profiling', 'Hot Path'] },

  // Architecture
  { term: 'Publish-Subscribe Pattern', abbr: 'Pub/Sub', category: 'Architecture', definition: 'A messaging pattern where publishers send events to a topic without knowing subscribers, and subscribers receive only the event types they register for, enabling loose coupling.', related: ['Event-Driven Architecture', 'Message Queue', 'Event Streaming'] },
  { term: 'Transactional Outbox', abbr: null, category: 'Architecture', definition: 'A pattern that writes events to an outbox table in the same database transaction as the business operation, then a relay publishes them reliably to a message broker.', related: ['Event-Driven Architecture', 'Exactly-Once Semantics', 'Change Data Capture'] },
  { term: 'Backend for Frontend', abbr: 'BFF', category: 'Architecture', definition: 'A dedicated backend service tailored to a specific client type — web, mobile, IoT — aggregating and shaping APIs so each frontend gets an optimized interface.', related: ['API Composition', 'API Gateway', 'Microservices Architecture'] },
  { term: 'Cell-Based Architecture', abbr: null, category: 'Architecture', definition: 'Partitioning a system into isolated cells that each handle a subset of traffic, limiting blast radius and allowing independent scaling and deployment per cell.', related: ['Fault Domain', 'Blast Radius', 'Multi-Region Architecture'] },
  { term: 'Active-Active Architecture', abbr: null, category: 'Architecture', definition: 'Running multiple sites or regions simultaneously serving live traffic, with data synchronized between them, providing zero-downtime failover and geographic load distribution.', related: ['High Availability', 'Failover', 'Multi-Region Architecture'] },

  // Cloud Native
  { term: 'Container Network Interface', abbr: 'CNI', category: 'Cloud Native', definition: 'A specification and plugin framework for configuring network interfaces in Linux containers, used by Kubernetes to assign IPs and set up pod networking.', related: ['CNI Plugin', 'Kubernetes', 'Network Policy'] },
  { term: 'HTTPRoute', abbr: null, category: 'Cloud Native', definition: 'A Kubernetes Gateway API resource defining HTTP routing rules — hostnames, paths, headers — to backend services, replacing legacy Ingress annotations with a richer, role-oriented model.', related: ['Gateway API', 'Ingress', 'GRPCRoute'] },
  { term: 'GRPCRoute', abbr: null, category: 'Cloud Native', definition: 'A Gateway API resource for routing gRPC traffic based on service and method names, bringing typed RPC routing to Kubernetes ingress controllers.', related: ['HTTPRoute', 'gRPC', 'Gateway API'] },
  { term: 'Dapr', abbr: 'Distributed Application Runtime', category: 'Cloud Native', definition: 'A CNCF runtime that provides portable building blocks — service invocation, state management, pub/sub, secrets — as sidecar APIs decoupling application code from infrastructure.', related: ['Sidecar Pattern', 'Microservices', 'Cloud Native'] },
  { term: 'SPIFFE', abbr: 'Secure Production Identity Framework for Everyone', category: 'Cloud Native', definition: 'An open standard for identifying and authenticating workloads in dynamic infrastructure using cryptographically verifiable SPIFFE IDs and SVID certificates.', related: ['SPIRE', 'Workload Identity', 'mTLS'] },
  { term: 'Seccomp Profile', abbr: null, category: 'Cloud Native', definition: 'A Linux secure-computing profile that restricts which system calls a container process may invoke, reducing the attack surface if a container is compromised.', related: ['Pod Security Standards', 'Runtime Security', 'AppArmor Profile'] },

  // Cloud Providers
  { term: 'Google GKE', abbr: 'Google Kubernetes Engine', category: 'Cloud Providers', definition: 'Google Cloud\'s managed Kubernetes service providing automated cluster management, node auto-repair, integrated logging and Cloud Operations observability.', related: ['Kubernetes', 'Amazon EKS', 'Azure AKS'] },
  { term: 'Azure AKS', abbr: 'Azure Kubernetes Service', category: 'Cloud Providers', definition: 'Microsoft Azure\'s managed Kubernetes offering with integrated Azure Active Directory, Azure Monitor and Azure Container Registry for enterprise deployments.', related: ['Kubernetes', 'Amazon EKS', 'Google GKE'] },
  { term: 'AWS ECS', abbr: 'Elastic Container Service', category: 'Cloud Providers', definition: 'Amazon\'s container orchestration service for running Docker containers on EC2 or Fargate without managing Kubernetes, integrated with CloudWatch and IAM.', related: ['AWS Fargate', 'Container Orchestration', 'Amazon EKS'] },
  { term: 'Google Cloud Run', abbr: null, category: 'Cloud Providers', definition: 'A fully managed serverless platform for running stateless containers that scales to zero, charged per request and compute-second with automatic HTTPS.', related: ['Serverless', 'Function as a Service', 'Azure Container Apps'] },
  { term: 'Azure Container Apps', abbr: null, category: 'Cloud Providers', definition: 'Microsoft\'s serverless container platform built on Kubernetes, supporting scale-to-zero, Dapr integration and event-driven autoscaling via KEDA.', related: ['Serverless', 'Dapr', 'Google Cloud Run'] },

  // Compute & Runtime
  { term: 'eBPF Program', abbr: null, category: 'Compute & Runtime', definition: 'A sandboxed bytecode program loaded into the Linux kernel that hooks network, security and observability events with near-native performance and without kernel modules.', related: ['eBPF', 'Tracepoint', 'Cilium'] },
  { term: 'JIT Compiler', abbr: 'Just-in-Time Compiler', category: 'Compute & Runtime', definition: 'A runtime compiler that translates bytecode to native machine code during execution, balancing startup speed with peak performance — used by the JVM, JavaScript engines and PyTorch.', related: ['JVM', 'Garbage Collection', 'Ahead-of-Time Compilation'] },
  { term: 'ZGC', abbr: 'Z Garbage Collector', category: 'Compute & Runtime', definition: 'A low-latency, scalable garbage collector in the JVM that keeps pause times under 1 ms regardless of heap size, suitable for large-memory, latency-sensitive Java services.', related: ['Garbage Collection', 'G1 GC', 'GC Pause'] },
  { term: 'Coroutine', abbr: null, category: 'Compute & Runtime', definition: 'A lightweight, cooperatively scheduled execution unit that can suspend and resume without blocking a thread, enabling high-concurrency I/O in languages like Python, Kotlin and C++.', related: ['Async Runtime', 'Goroutine', 'Event Loop'] },
  { term: 'Tokio', abbr: null, category: 'Compute & Runtime', definition: 'An asynchronous runtime for Rust providing an event loop, task scheduler and I/O primitives, powering most production Rust network services and observability agents.', related: ['Async Runtime', 'Coroutine', 'Vector'] },

  // Containers
  { term: 'BuildKit', abbr: null, category: 'Containers', definition: 'A modern container image build engine with parallel stage execution, advanced caching, multi-platform builds and Dockerfile-free frontends, used by Docker Buildx.', related: ['Multi-Stage Build', 'Dockerfile', 'Kaniko'] },
  { term: 'Docker Compose', abbr: null, category: 'Containers', definition: 'A tool for defining and running multi-container applications from a YAML file, managing networks, volumes and dependencies for local development and testing.', related: ['Docker', 'Container Orchestration', 'Docker Compose File'] },
  { term: 'Cosign', abbr: null, category: 'Containers', definition: 'A Sigstore tool for signing and verifying container images with keyless OIDC-based signing, enabling supply-chain trust without managing long-lived keys.', related: ['Sigstore', 'Image Signing', 'Software Supply Chain'] },
  { term: 'Trivy', abbr: null, category: 'Containers', definition: 'An open-source vulnerability scanner for container images, filesystems and IaC configs, detecting CVEs in OS packages and application dependencies.', related: ['Image Scanning', 'Container Security', 'SBOM'] },
  { term: 'OverlayFS', abbr: null, category: 'Containers', definition: 'A union filesystem that layers multiple directories into a single merged view, forming the basis of container image layers and copy-on-write storage.', related: ['Layer (Image)', 'Union Filesystem', 'Container Image'] },

  // Data & Streaming
  { term: 'Kafka Connect', abbr: null, category: 'Data & Streaming', definition: 'A framework for streaming data between Apache Kafka and external systems — databases, S3, Elasticsearch — using pluggable source and sink connectors.', related: ['Kafka', 'Debezium', 'Event Streaming'] },
  { term: 'Kafka Streams', abbr: null, category: 'Data & Streaming', definition: 'A Java library for building real-time stream processing applications that read from, transform and write back to Kafka topics without a separate processing cluster.', related: ['Kafka', 'Stream Processing', 'Event Streaming'] },
  { term: 'Debezium', abbr: null, category: 'Data & Streaming', definition: 'An open-source change-data-capture platform that streams database row-level changes into Kafka, enabling event-driven architectures from existing OLTP databases.', related: ['Change Data Capture', 'Kafka Connect', 'Transactional Outbox'] },
  { term: 'Exactly-Once Semantics', abbr: null, category: 'Data & Streaming', definition: 'A delivery guarantee ensuring each message is processed precisely one time even through failures and retries, requiring idempotent consumers and transactional producers.', related: ['At-Least-Once Delivery', 'Idempotence', 'Kafka'] },
  { term: 'Tumbling Window', abbr: null, category: 'Data & Streaming', definition: 'A fixed-size, non-overlapping time window for aggregating stream events — e.g. count requests per minute — where each event belongs to exactly one window.', related: ['Sliding Window', 'Windowing', 'Stream Processing'] },
  { term: 'Kappa Architecture', abbr: null, category: 'Data & Streaming', definition: 'A streaming-only data architecture where all data is processed through a single stream pipeline, avoiding the batch layer of Lambda Architecture for simpler operations.', related: ['Lambda Architecture', 'Stream Processing', 'Event Streaming'] },

  // Data Formats
  { term: 'JSON Schema', abbr: null, category: 'Data Formats', definition: 'A vocabulary for annotating JSON documents with types, required fields and constraints, enabling validation, documentation and code generation from API payloads.', related: ['JSON', 'OpenAPI Specification', 'Structured Output'] },
  { term: 'OpenAPI Specification', abbr: 'OAS', category: 'Data Formats', definition: 'A standard, language-agnostic format for describing REST API endpoints, parameters, request/response schemas and authentication — the successor to Swagger.', related: ['REST', 'JSON Schema', 'API'] },
  { term: 'AsyncAPI', abbr: null, category: 'Data Formats', definition: 'An open specification for describing event-driven and message-based APIs — channels, messages, bindings — analogous to OpenAPI for asynchronous systems.', related: ['Event-Driven Architecture', 'Message Queue', 'OpenAPI Specification'] },
  { term: 'Apache Arrow', abbr: null, category: 'Data Formats', definition: 'A cross-language columnar in-memory format for analytics, enabling zero-copy data sharing between processes, databases and ML frameworks at high speed.', related: ['Parquet', 'Columnar Storage', 'Feather Format'] },
  { term: 'HCL', abbr: 'HashiCorp Configuration Language', category: 'Data Formats', definition: 'A human-readable configuration language used by Terraform, Vault and other HashiCorp tools, supporting blocks, attributes, expressions and type constraints.', related: ['Terraform', 'YAML', 'Infrastructure as Code'] },

  // Databases
  { term: 'ClickHouse', abbr: null, category: 'Databases', definition: 'An open-source columnar OLAP database optimized for real-time analytical queries over billions of rows, widely used for observability metrics and log analytics.', related: ['Columnar Storage', 'OLAP', 'Time Series Database'] },
  { term: 'TimescaleDB', abbr: null, category: 'Databases', definition: 'A PostgreSQL extension for time-series data with automatic partitioning, compression and continuous aggregates, combining SQL familiarity with TSDB performance.', related: ['Time Series Database', 'PostgreSQL', 'InfluxDB'] },
  { term: 'DuckDB', abbr: null, category: 'Databases', definition: 'An in-process analytical SQL database (embedded OLAP) that runs inside applications for fast local analytics on Parquet, CSV and Arrow data without a server.', related: ['OLAP', 'Apache Arrow', 'Parquet'] },
  { term: 'HTAP', abbr: 'Hybrid Transactional/Analytical Processing', category: 'Databases', definition: 'A database architecture supporting both OLTP row-oriented writes and OLAP columnar analytics on the same dataset without ETL to a separate warehouse.', related: ['OLTP', 'OLAP', 'CockroachDB'] },
  { term: 'Columnar Storage', abbr: null, category: 'Databases', definition: 'A data layout storing values column-by-column rather than row-by-row, enabling efficient compression and fast aggregation scans for analytical workloads.', related: ['OLAP', 'Parquet', 'ClickHouse'] },

  // DevOps & CI/CD
  { term: 'GitHub Actions', abbr: null, category: 'DevOps & CI/CD', definition: 'GitHub\'s integrated CI/CD platform using YAML workflows triggered by repository events to build, test, deploy and automate any software pipeline.', related: ['Continuous Integration', 'Pipeline (CI/CD)', 'GitLab CI'] },
  { term: 'GitLab CI', abbr: null, category: 'DevOps & CI/CD', definition: 'GitLab\'s built-in continuous integration system using .gitlab-ci.yml pipelines with stages, runners and integrated container registry for end-to-end DevOps.', related: ['Continuous Integration', 'GitHub Actions', 'Pipeline (CI/CD)'] },
  { term: 'Semantic Versioning', abbr: 'SemVer', category: 'DevOps & CI/CD', definition: 'A versioning scheme MAJOR.MINOR.PATCH where major bumps indicate breaking changes, minor adds features and patch fixes bugs, enabling predictable dependency management.', related: ['Version Control', 'Release Management', 'Artifact'] },
  { term: 'Monorepo', abbr: null, category: 'DevOps & CI/CD', definition: 'A single version-controlled repository containing multiple projects or services, enabling atomic cross-service changes and shared tooling at the cost of scale complexity.', related: ['Polyrepo', 'Repository', 'Trunk-Based Development'] },
  { term: 'Trunk-Based Development', abbr: null, category: 'DevOps & CI/CD', definition: 'A branching strategy where developers commit small, frequent changes directly to a single main branch, supported by feature flags and CI to avoid long-lived feature branches.', related: ['Continuous Integration', 'Feature Flag', 'DORA Metrics'] },

  // Digital Experience
  { term: 'Long Task', abbr: null, category: 'Digital Experience', definition: 'A browser main-thread operation lasting 50 ms or more that blocks user interaction, contributing to poor Interaction to Next Paint and frustration signals.', related: ['Total Blocking Time', 'Main Thread Blocking', 'Interaction to Next Paint'] },
  { term: 'Critical Rendering Path', abbr: null, category: 'Digital Experience', definition: 'The sequence of steps — HTML parse, CSSOM, layout, paint — the browser follows to render initial content; optimizing it improves First Contentful Paint and LCP.', related: ['First Contentful Paint', 'Render-Blocking Resource', 'Largest Contentful Paint'] },
  { term: 'Resource Timing API', abbr: null, category: 'Digital Experience', definition: 'A browser API exposing detailed load timing for each resource — DNS, TCP, TLS, download — enabling waterfall analysis of page performance bottlenecks.', related: ['Network Waterfall', 'Navigation Timing API', 'Time to First Byte'] },
  { term: 'Lazy Loading', abbr: null, category: 'Digital Experience', definition: 'Deferring the load of off-screen images, scripts or components until they are needed, reducing initial page weight and improving Core Web Vitals scores.', related: ['Largest Contentful Paint', 'Critical Rendering Path', 'First Contentful Paint'] },
  { term: 'Progressive Web App Performance', abbr: 'PWA Performance', category: 'Digital Experience', definition: 'Optimizing installable web apps for offline capability, fast repeat visits via service-worker caching and native-like responsiveness on mobile devices.', related: ['Service Worker Cache', 'Core Web Vitals', 'Mobile Core Web Vitals'] },

  // Distributed Systems
  { term: 'Bloom Filter', abbr: null, category: 'Distributed Systems', definition: 'A space-efficient probabilistic data structure that tests set membership with possible false positives but no false negatives, used in caches, databases and CDNs.', related: ['HyperLogLog', 'Count-Min Sketch', 'Caching'] },
  { term: 'Token Bucket', abbr: null, category: 'Distributed Systems', definition: 'A rate-limiting algorithm that allows bursts up to bucket capacity while refilling tokens at a steady rate, smoothing traffic to protect downstream services.', related: ['Rate Limiting', 'Leaky Bucket', 'Throttling'] },
  { term: 'Merkle Tree', abbr: null, category: 'Distributed Systems', definition: 'A hash tree where each non-leaf node is the hash of its children, enabling efficient verification of large datasets and synchronization between replicas.', related: ['Consensus', 'Replication', 'Distributed System'] },
  { term: 'Byzantine Fault Tolerance', abbr: 'BFT', category: 'Distributed Systems', definition: 'The ability of a distributed system to reach consensus even when some nodes fail arbitrarily or act maliciously, at the cost of higher communication overhead.', related: ['Consensus', 'Raft', 'Fault Tolerance'] },
  { term: 'Distributed Cache', abbr: null, category: 'Distributed Systems', definition: 'A cache shared across multiple application instances or services — Redis, Memcached — reducing database load and improving response times with cache-coherency challenges.', related: ['Redis', 'Memcached', 'Cache Invalidation'] },

  // Fundamentals
  { term: 'Observability Pipeline', abbr: null, category: 'Fundamentals', definition: 'The end-to-end flow from instrumentation through collection, processing, storage and visualization of telemetry data, often including routing, sampling and cost controls.', related: ['Telemetry Pipeline', 'Instrumentation', 'Observability'] },
  { term: 'Incident Lifecycle', abbr: null, category: 'Fundamentals', definition: 'The stages an incident passes through — detection, triage, investigation, mitigation, resolution, postmortem — each with defined roles, artifacts and time targets.', related: ['Incident Management', 'Postmortem', 'Mean Time to Recovery'] },
  { term: 'Availability Target', abbr: null, category: 'Fundamentals', definition: 'The desired percentage of time a service is operational and serving correct responses, typically expressed in nines (99.9%, 99.99%) and formalized as an SLO.', related: ['Service Level Objective', 'Uptime', 'Nines'] },
  { term: 'Dynamic Threshold', abbr: null, category: 'Fundamentals', definition: 'An alert threshold that adapts to seasonal patterns, trends or ML-predicted baselines rather than using a fixed static value, reducing false positives.', related: ['Static Threshold', 'Anomaly Score', 'Baseline Deviation'] },
  { term: 'Performance Baseline', abbr: null, category: 'Fundamentals', definition: 'A reference measurement of normal system behavior — latency, throughput, error rate — used to detect regressions and set meaningful alert thresholds.', related: ['Synthetic Baseline', 'Baseline Deviation', 'Service Level Indicator'] },

  // Incident
  { term: 'Incident Response Plan', abbr: 'IRP', category: 'Incident', definition: 'A documented playbook defining roles, communication channels, escalation paths and procedures for handling security or operational incidents before they occur.', related: ['Incident Management', 'Runbook', 'Escalation Matrix'] },
  { term: 'Emergency Change', abbr: null, category: 'Incident', definition: 'An urgent production modification made during an active incident to restore service, documented and reviewed post-hoc per ITIL change management.', related: ['Mitigation', 'Change Management', 'Rollback'] },
  { term: 'Lessons Learned', abbr: null, category: 'Incident', definition: 'Actionable insights captured in a postmortem about what went well, what failed and what to change — fed back into runbooks, monitoring and architecture.', related: ['Postmortem', 'Corrective Action', 'Blameless Postmortem'] },
  { term: 'Action Item Tracking', abbr: null, category: 'Incident', definition: 'Following postmortem remediation tasks — fix bugs, add alerts, update runbooks — to completion with owners and deadlines, preventing repeat incidents.', related: ['Postmortem', 'Corrective Action', 'Preventive Action'] },
  { term: 'Bridge Call', abbr: null, category: 'Incident', definition: 'A live audio or video conference convened during a major incident where responders coordinate in real time, distinct from the async incident chat channel.', related: ['War Room', 'Incident Commander', 'Major Incident'] },

  // Infrastructure
  { term: 'NUMA Node', abbr: 'Non-Uniform Memory Access', category: 'Infrastructure', definition: 'A hardware grouping of CPUs and local memory where accessing remote NUMA memory is slower, affecting performance if workloads are not NUMA-aware.', related: ['CPU Affinity', 'NUMA Awareness', 'CPU Socket'] },
  { term: 'CPU Pinning', abbr: null, category: 'Infrastructure', definition: 'Binding a process or container to specific CPU cores to improve cache locality and eliminate scheduler migration overhead for latency-sensitive workloads.', related: ['CPU Affinity', 'CPU Core', 'NUMA Node'] },
  { term: 'Huge Pages', abbr: null, category: 'Infrastructure', definition: 'Memory pages larger than the default 4 KB (typically 2 MB or 1 GB), reducing TLB misses and improving performance for memory-intensive applications like databases.', related: ['Transparent Huge Pages', 'Memory Utilization', 'NUMA Node'] },
  { term: 'Page Cache', abbr: null, category: 'Infrastructure', definition: 'Kernel-managed RAM caching recently read filesystem blocks, speeding up disk I/O. High page cache usage is normal; pressure here can indicate memory contention.', related: ['Buffer Cache', 'Disk Latency', 'Memory Utilization'] },
  { term: 'Jumbo Frames', abbr: null, category: 'Infrastructure', definition: 'Ethernet frames larger than the standard 1500-byte MTU (often 9000 bytes), reducing packet overhead and improving throughput on data-center networks.', related: ['MTU', 'Network Throughput', 'Bandwidth'] },

  // IT Operations
  { term: 'Known Error Database', abbr: 'KEDB', category: 'IT Operations', definition: 'An ITIL repository of documented problems with known root causes and workarounds, helping service desk agents resolve recurring incidents faster.', related: ['Problem Management', 'Workaround', 'CMDB'] },
  { term: 'Standard Change', abbr: null, category: 'IT Operations', definition: 'A pre-approved, low-risk, repeatable change with documented procedures — like patching or certificate renewal — that bypasses full change advisory review.', related: ['Change Management', 'Change Advisory Board', 'Normal Change'] },
  { term: 'Impact Analysis', abbr: null, category: 'IT Operations', definition: 'Assessing which services, users and business processes will be affected by a proposed change or active incident, guiding prioritization and communication.', related: ['Customer Impact', 'Dependency Mapping', 'Change Management'] },
  { term: 'Service Transition', abbr: null, category: 'IT Operations', definition: 'The ITIL lifecycle stage for moving new or changed services into production — testing, knowledge transfer, CMDB updates and operational readiness checks.', related: ['Operational Readiness', 'Change Management', 'ITIL'] },
  { term: 'Continual Service Improvement', abbr: 'CSI', category: 'IT Operations', definition: 'The ITIL practice of systematically identifying and implementing improvements to service quality, processes and outcomes based on metrics and feedback.', related: ['ITIL', 'Service Measurement', 'Lessons Learned'] },

  // Kubernetes
  { term: 'Kube-Scheduler', abbr: null, category: 'Kubernetes', definition: 'The Kubernetes control-plane component that assigns pending pods to nodes based on resource requests, affinity rules, taints and topology constraints.', related: ['Kubelet', 'Node Affinity', 'Taint'] },
  { term: 'Control Plane Node', abbr: null, category: 'Kubernetes', definition: 'A cluster node running Kubernetes control-plane components — API server, scheduler, controller-manager, etcd — that manages workload orchestration.', related: ['Worker Node', 'API Server', 'etcd'] },
  { term: 'Node Drain', abbr: null, category: 'Kubernetes', definition: 'Gracefully evicting all pods from a node before maintenance or decommissioning, respecting PodDisruptionBudgets and rescheduling workloads elsewhere.', related: ['Node Cordon', 'Pod Disruption Budget', 'Eviction'] },
  { term: 'Limit Range', abbr: null, category: 'Kubernetes', definition: 'A namespace policy setting default and maximum CPU/memory requests and limits for pods and containers, preventing resource hogging in shared clusters.', related: ['Resource Quota', 'Resource Limit', 'Resource Request'] },
  { term: 'Pod Security Admission', abbr: null, category: 'Kubernetes', definition: 'The built-in Kubernetes admission controller enforcing Pod Security Standards (privileged, baseline, restricted) at namespace level to harden workload security.', related: ['Pod Security Standards', 'Admission Controller', 'Seccomp Profile'] },

  // Logging
  { term: 'LogQL', abbr: null, category: 'Logging', definition: 'Grafana Loki\'s query language for filtering, parsing and aggregating log streams — similar in spirit to PromQL but designed for label-based log queries.', related: ['Loki', 'Log Query Language', 'PromQL'] },
  { term: 'Log Forwarder', abbr: null, category: 'Logging', definition: 'An agent or service that receives logs from applications or collectors and routes them to one or more destinations — aggregators, SIEMs, archival storage.', related: ['Log Shipper', 'Log Collector', 'Fluent Bit'] },
  { term: 'Log Masking', abbr: null, category: 'Logging', definition: 'Automatically redacting or obfuscating sensitive fields — passwords, tokens, PII — in log output before storage or transmission to meet compliance requirements.', related: ['Log Redaction', 'PII', 'Structured Logging'] },
  { term: 'Log Pipeline', abbr: null, category: 'Logging', definition: 'A configured sequence of stages — collect, parse, filter, enrich, buffer, ship — that processes log data from source to destination with transformations along the way.', related: ['Telemetry Pipeline', 'Log Enrichment', 'Log Shipper'] },
  { term: 'Log Archival', abbr: null, category: 'Logging', definition: 'Moving aged log data from hot, expensive storage to cold, low-cost archival tiers (S3 Glacier, GCS Coldline) per retention policy while keeping it queryable.', related: ['Log Retention', 'Cold Storage Log', 'Data Tiering'] },

  // Metrics
  { term: 'PromQL', abbr: 'Prometheus Query Language', category: 'Metrics', definition: 'The functional query language for Prometheus that selects, aggregates, rates and joins time-series data — e.g. rate(http_requests_total[5m]) — for dashboards and alerts.', related: ['Prometheus', 'Recording Rule', 'Alerting Rule'] },
  { term: 'Metric Relabeling', abbr: null, category: 'Metrics', definition: 'Rewriting label sets on scraped metrics before ingestion — dropping high-cardinality labels, adding environment tags — to control storage cost and query clarity.', related: ['Target Relabeling', 'Metric Label', 'Cardinality'] },
  { term: 'Downsampling', abbr: null, category: 'Metrics', definition: 'Reducing the resolution of older time-series data by averaging or maxing values over wider intervals, cutting long-term storage cost while preserving trends.', related: ['Rollup', 'Granularity', 'Data Tiering'] },
  { term: 'Derived Metric', abbr: null, category: 'Metrics', definition: 'A calculated metric composed from raw metrics — error rate as errors/requests, saturation as usage/capacity — defined in queries or recording rules.', related: ['Recording Rule', 'Composite Metric', 'Calculated Metric'] },
  { term: 'Histogram Quantile', abbr: null, category: 'Metrics', definition: 'Estimating percentiles (p50, p95, p99) from Prometheus histogram buckets using the histogram_quantile function, the standard approach for latency SLIs.', related: ['Histogram', 'Quantile', 'P99 Latency'] },

  // Networking
  { term: 'VXLAN', abbr: 'Virtual Extensible LAN', category: 'Networking', definition: 'A network virtualization overlay that encapsulates L2 frames in UDP packets, enabling large-scale multi-tenant layer-2 networks across layer-3 infrastructure.', related: ['Geneve', 'CNI', 'Flannel'] },
  { term: 'WireGuard', abbr: null, category: 'Networking', definition: 'A modern, lightweight VPN protocol using state-of-the-art cryptography with simpler configuration and better performance than IPsec or OpenVPN.', related: ['VPN', 'Tunnel', 'mTLS'] },
  { term: 'Spine-Leaf Architecture', abbr: null, category: 'Networking', definition: 'A two-tier data-center network topology where every leaf switch connects to every spine switch, providing predictable latency and high bisection bandwidth.', related: ['Clos Network', 'Top-of-Rack Switch', 'Fat Tree Topology'] },
  { term: 'CoreDNS', abbr: null, category: 'Networking', definition: 'The default DNS server in Kubernetes, a flexible, plugin-based DNS resolver handling cluster service discovery, stub zones and custom records.', related: ['DNS', 'Service Discovery', 'External DNS'] },
  { term: 'eBPF Networking', abbr: null, category: 'Networking', definition: 'Using eBPF programs in the kernel to implement high-performance networking features — load balancing, encryption, observability — without iptables or kernel modules.', related: ['eBPF Program', 'Cilium', 'iptables'] },

  // Reliability
  { term: 'Graceful Startup', abbr: null, category: 'Reliability', definition: 'A controlled service initialization sequence — warming caches, waiting for dependencies, passing readiness probes — before accepting production traffic.', related: ['Readiness Probe', 'Health Check', 'Graceful Shutdown'] },
  { term: 'Degraded Mode', abbr: null, category: 'Reliability', definition: 'Operating with reduced functionality when dependencies fail — serving cached data, disabling non-critical features — rather than complete outage.', related: ['Graceful Degradation', 'Fallback Response', 'Circuit Breaker'] },
  { term: 'Chaos Experiment', abbr: null, category: 'Reliability', definition: 'A controlled test injecting a specific failure — pod kill, network partition, CPU stress — to validate system resilience against a steady-state hypothesis.', related: ['Chaos Engineering', 'Fault Injection', 'Steady State Hypothesis'] },
  { term: 'Steady State Hypothesis', abbr: null, category: 'Reliability', definition: 'The measurable definition of normal system behavior — error rate below 1%, p99 under 500 ms — used as the pass/fail criterion during a chaos experiment.', related: ['Chaos Experiment', 'Service Level Objective', 'Health Check'] },
  { term: 'Maintenance Window', abbr: null, category: 'Reliability', definition: 'A scheduled period for planned changes or infrastructure work where reduced availability is expected and communicated to stakeholders in advance.', related: ['Planned Downtime', 'Change Management', 'Status Page'] },

  // Security & SIEM
  { term: 'Sigma Rule', abbr: null, category: 'Security & SIEM', definition: 'A vendor-agnostic YAML format for describing log-detection logic, convertible to Splunk, Elastic, Sentinel and other SIEM query languages.', related: ['Detection Rule', 'SIEM', 'Correlation Rule'] },
  { term: 'STIX', abbr: 'Structured Threat Information Expression', category: 'Security & SIEM', definition: 'A standardized JSON language for representing cyber-threat intelligence — indicators, TTPs, threat actors — enabling machine-readable sharing between organizations.', related: ['TAXII', 'Threat Intelligence', 'Indicator of Compromise'] },
  { term: 'TAXII', abbr: 'Trusted Automated Exchange of Intelligence Information', category: 'Security & SIEM', definition: 'An application protocol for securely transporting STIX threat-intelligence feeds between producers and consumers over HTTPS.', related: ['STIX', 'Threat Feed', 'Threat Intelligence'] },
  { term: 'NetFlow', abbr: null, category: 'Security & SIEM', definition: 'A network protocol exporting metadata about IP traffic flows — source, destination, ports, bytes — for bandwidth analysis, anomaly detection and forensic investigation.', related: ['sFlow', 'IPFIX', 'Network Monitoring'] },
  { term: 'Threat Model', abbr: null, category: 'Security & SIEM', definition: 'A structured analysis identifying assets, adversaries, attack vectors and mitigations for a system, guiding security controls and detection rule design.', related: ['Attack Surface', 'MITRE ATT&CK', 'Security Posture'] },

  // Service Mesh
  { term: 'Virtual Service', abbr: null, category: 'Service Mesh', definition: 'An Istio resource defining routing rules — host matching, HTTP routes, retries, timeouts — that control how traffic reaches destination services in the mesh.', related: ['Destination Rule', 'Istio', 'Traffic Splitting'] },
  { term: 'Destination Rule', abbr: null, category: 'Service Mesh', definition: 'An Istio resource configuring policies applied to traffic after routing — load balancing, connection pools, circuit breaking, TLS mode — for a service subset.', related: ['Virtual Service', 'Istio', 'Outlier Detection'] },
  { term: 'Waypoint Proxy', abbr: null, category: 'Service Mesh', definition: 'An ambient-mesh L7 proxy in Istio that handles HTTP routing, authorization and telemetry per workload group without requiring a sidecar on every pod.', related: ['Istio', 'Ztunnel', 'Service Mesh'] },
  { term: 'Strict mTLS', abbr: null, category: 'Service Mesh', definition: 'A service-mesh TLS mode that rejects any plaintext traffic to a workload, enforcing encrypted mutual authentication for all connections.', related: ['mTLS', 'Peer Authentication', 'Permissive mTLS'] },
  { term: 'SPIRE', abbr: 'SPIFFE Runtime Environment', category: 'Service Mesh', definition: 'A production-ready implementation of SPIFFE that issues and rotates short-lived SVID identity documents to workloads, forming the trust foundation for zero-trust meshes.', related: ['SPIFFE', 'Workload Identity', 'Certificate Rotation'] },

  // Standards & Tools
  { term: 'OpenTelemetry Collector', abbr: null, category: 'Standards & Tools', definition: 'A vendor-neutral agent that receives, processes and exports telemetry via OTLP, supporting batching, filtering, sampling and routing to any backend.', related: ['OpenTelemetry', 'OTLP Protocol', 'otel-collector'] },
  { term: 'OTLP Protocol', abbr: 'OpenTelemetry Protocol', category: 'Standards & Tools', definition: 'The standard wire format for exporting metrics, logs and traces from OpenTelemetry SDKs and collectors to observability backends over gRPC or HTTP.', related: ['OpenTelemetry', 'OTLP Exporter', 'OpenTelemetry Collector'] },
  { term: 'Blackbox Exporter', abbr: null, category: 'Standards & Tools', definition: 'A Prometheus exporter that probes endpoints over HTTP, HTTPS, DNS, TCP and ICMP, generating uptime and latency metrics for external and internal services.', related: ['Prometheus Exporter', 'Synthetic Monitoring', 'Uptime Monitoring'] },
  { term: 'Vector Remap Language', abbr: 'VRL', category: 'Standards & Tools', definition: 'A domain-specific transformation language in the Vector observability pipeline for parsing, filtering, enriching and reshaping logs and metrics at collection time.', related: ['Vector', 'Log Transformation', 'Telemetry Pipeline'] },
  { term: 'K6 Load Testing', abbr: null, category: 'Standards & Tools', definition: 'An open-source load-testing tool using JavaScript test scripts to simulate traffic, measure latency and validate SLOs under stress before production releases.', related: ['Synthetic Monitoring', 'Performance Monitoring', 'Gatling'] },

  // Tracing
  { term: 'OTLP Exporter', abbr: null, category: 'Tracing', definition: 'An OpenTelemetry component that serializes spans and sends them to a collector or backend using the OTLP protocol over gRPC or HTTP.', related: ['OTLP Protocol', 'Span Exporter', 'OpenTelemetry Collector'] },
  { term: 'Batch Span Processor', abbr: null, category: 'Tracing', definition: 'An OpenTelemetry span processor that accumulates spans and exports them in batches, balancing export efficiency against added latency from buffering.', related: ['Span Processor', 'Simple Span Processor', 'Trace Exporter'] },
  { term: 'Parent-Based Sampling', abbr: null, category: 'Tracing', definition: 'A sampling strategy where child spans inherit the sampling decision of their parent, ensuring complete sub-trees within a sampled trace.', related: ['Head-Based Sampling', 'Trace Sampling Rate', 'Sampling Decision'] },
  { term: 'Resource Detection', abbr: null, category: 'Tracing', definition: 'Automatically discovering and attaching resource attributes — service name, host, cloud region, K8s pod — to telemetry via OpenTelemetry resource detectors.', related: ['Resource Attributes', 'OpenTelemetry', 'Semantic Conventions'] },
  { term: 'Trace Ingestion', abbr: null, category: 'Tracing', definition: 'The pipeline stage where a trace backend receives, validates, indexes and stores incoming spans from collectors or agents for query and analysis.', related: ['Trace Backend', 'Tempo', 'Jaeger Collector'] },

  // Visualization
  { term: 'Line Chart', abbr: null, category: 'Visualization', definition: 'A graph connecting data points with lines to show metric trends over time, the default panel type for time-series observability dashboards.', related: ['Time Series Chart', 'Dashboard Panel', 'Area Chart'] },
  { term: 'Gauge Chart', abbr: null, category: 'Visualization', definition: 'A radial or arc visualization showing a single metric value against a min-max range, commonly used for CPU usage, disk space and SLO compliance.', related: ['Single Stat Panel', 'Dashboard', 'Gauge'] },
  { term: 'Template Variable', abbr: null, category: 'Visualization', definition: 'A dashboard dropdown or input that parameterizes panel queries — selecting environment, service or host — so one dashboard serves multiple contexts.', related: ['Dashboard Variable', 'Dashboard', 'Panel Query'] },
  { term: 'Panel Threshold', abbr: null, category: 'Visualization', definition: 'Colored value boundaries on a dashboard panel that visually highlight when a metric enters warning or critical ranges without a separate alert.', related: ['Dashboard Panel', 'Alerting Rule', 'Color Scheme'] },
  { term: 'Time Range Picker', abbr: null, category: 'Visualization', definition: 'A dashboard control for selecting the query time window — last hour, 7 days, custom range — with optional auto-refresh interval for live monitoring.', related: ['Refresh Interval Dashboard', 'Dashboard', 'Granularity'] },
];
